const PHAPLUAT_DATA = {"daily": {"01/01/2026": {"question": "Đồng chí cho biết Nghị định 15/2020/NĐ-CP quy định xử phạt vi phạm hành chính trong lĩnh vực bưu chính, viễn thông, tần số vô tuyến điện, công nghệ thông tin và giao dịch điện tử gồm mấy chương, mấy điều?", "answer": "Gồm 9 chương, 124 điều."}, "02/01/2026": {"question": "Đồng chí cho biết, theo Điều 5 của Nghị định 15/2020/NĐ-CP, đối với hành vi thông báo không đúng với cơ quan nhà nước có thẩm quyền về bưu chính khi có thay đổi liên quan đến Giấy phép bưu chính theo quy định của pháp luật thì bị phạt như thế nào?", "answer": "Theo khoản 1, Điều 5 của Nghị định 15/2020/NĐ-CP, bị phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng."}, "03/01/2026": {"question": "Đồng chí cho biết, theo Điều 5 của Nghị định 15/2020/NĐ-CP, đối với hành vi không thông báo với cơ quan nhà nước có thẩm quyền về bưu chính khi có thay đổi liên quan đến Giấy phép bưu chính theo quy định của pháp luật thì bị phạt như thế nào?", "answer": "Theo khoản 2, Điều 5 của Nghị định 15/2020/NĐ-CP, bị phạt tiền từ 5.000.000 đồng đến 7.000.000 đồng."}, "04/01/2026": {"question": "Đồng chí cho biết, theo Điều 6 của Nghị định 15/2020/NĐ-CP, đối với hành vi thông báo không đúng với cơ quan nhà nước có thẩm quyền về bưu chính khi có thay đổi liên quan đến văn bản xác nhận thông báo hoạt động bưu chính thì bị phạt như thế nào?", "answer": "Theo khoản 1, Điều 6 của Nghị định 15/2020/NĐ-CP, bị phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng."}, "05/01/2026": {"question": "Đồng chí cho biết, theo Điều 7 của Nghị định 15/2020/NĐ-CP, đối với hành vi sử dụng không đúng dấu ngày hoặc thể hiện không chính xác thông tin về thời gian, địa điểm chấp nhận bưu gửi trên hợp đồng hoặc chứng từ xác nhận việc chấp nhận bưu gửi  thì bị phạt như thế nào?", "answer": "Theo khoản 1, Điều 7 của Nghị định 15/2020/NĐ-CP, bị phạt tiền từ 1.000.000 đồng đến 3.000.000 đồng."}, "06/01/2026": {"question": "Đồng chí cho biết theo Luật tố cáo thì những trường hợp nào không thụ lý giải quyết?", "answer": "Theo khoản 2, điểu 20 Người có thẩm quyền không thụ lý giải quyết tố cáo trong các trường hợp sau đây:\n- Tố cáo về vụ việc đã được người đó giải quyết mà người tố cáo không cung cấp thông tin, tình tiết mới;\n- Tố cáo về vụ việc mà nội dung và những thông tin người tố cáo cung cấp không có cơ sở để xác định người vi phạm, hành vi vi phạm pháp luật;\n- Tố cáo về vụ việc mà người có thẩm quyền giải quyết tố cáo không đủ điều kiện để kiểm tra, xác minh hành vi vi phạm pháp luật, người vi phạm."}, "07/01/2026": {"question": "Đồng chí cho biết theo Luật tố cáo Chánh thanh tra Bộ, cơ quan ngang Bộ, Chánh thanh tra tỉnh, thành phố trực thuộc trung ương, Chánh thanh tra sở, Chánh thanh tra huyện, quận, thị xã, thành phố thuộc tỉnh có trách nhiệm như thế nào?", "answer": "Theo khoản 1, điều 23 Luật tố cáo quy định: Chánh thanh tra Bộ, cơ quan ngang Bộ, Chánh thanh tra tỉnh, thành phố trực thuộc trung ương, Chánh thanh tra sở, Chánh thanh tra huyện, quận, thị xã, thành phố thuộc tỉnh có trách nhiệm sau đây:\n- Xác minh nội dung tố cáo, kết luận nội dung xác minh, kiến nghị biện pháp xử lý tố cáo thuộc thẩm quyền giải quyết của người đứng đầu cơ quan hành chính nhà nước cùng cấp khi được giao;\n- Xem xét, kết luận việc giải quyết tố cáo mà người đứng đầu cơ quan cấp dưới trực tiếp của người đứng đầu cơ quan hành chính nhà nước cùng cấp đã giải quyết nhưng có dấu hiệu vi phạm pháp luật; trường hợp có căn cứ cho rằng việc giải quyết tố cáo có vi phạm pháp luật thì kiến nghị người đứng đầu cơ quan hành chính nhà nước cùng cấp xem xét, giải quyết lại."}, "08/01/2026": {"question": "Đồng chí cho biết theo Luật tố cáo Tổng Thanh tra Chính phủ có trách nhiệm như thế nào?", "answer": "Theo khoản 1, điều 23 Luật tố cáo quy định: Tổng Thanh tra Chính phủ có trách nhiệm sau đây:\n- Xác minh nội dung tố cáo, kết luận nội dung xác minh, kiến nghị biện pháp xử lý tố cáo thuộc thẩm quyền giải quyết của Thủ tướng Chính phủ khi được giao;\n- Xem xét, kết luận việc giải quyết tố cáo mà Bộ trưởng, Thủ trưởng cơ quan ngang Bộ, Thủ trưởng cơ quan thuộc Chính phủ, Chủ tịch Ủy ban nhân dân cấp tỉnh đã giải quyết nhưng có dấu hiệu vi phạm pháp luật; trường hợp kết luận việc giải quyết có vi phạm pháp luật thì kiến nghị Thủ tướng Chính phủ xem xét, giải quyết lại."}, "09/01/2026": {"question": "Đồng chí cho biết theo Luật tố cáo quy định kết luận tố cáo cần đạt được những nội dung nào?", "answer": "Theo điều 24, Luật tố cáo quy định về Kết luận nội dung tố cáo như sau :\n- Căn cứ vào nội dung tố cáo, văn bản giải trình của người bị tố cáo, kết quả xác minh nội dung tố cáo, tài liệu, chứng cứ có liên quan, người giải quyết tố cáo phải kết luận bằng văn bản về nội dung tố cáo.\n- Kết luận nội dung tố cáo phải có các nội dung sau đây:\n+ Kết quả xác minh nội dung tố cáo;\n+ Kết luận việc tố cáo đúng, đúng một phần hoặc sai; xác định trách nhiệm của từng cá nhân về những nội dung tố cáo đúng hoặc đúng một phần;\n+ Các biện pháp xử lý theo thẩm quyền; kiến nghị biện pháp xử lý với cơ quan, tổ chức, cá nhân có thẩm quyền (nếu có)."}, "10/01/2026": {"question": "Đồng chí cho biết theo Luật tố cáo quy định về việc tố cáo tiếp như thế nào?", "answer": "Theo điều 27, Luật tố cáo quy định việc tố cáo tiếp cụ thể như sau:\nTrường hợp quá thời hạn quy định mà tố cáo không được giải quyết hoặc có căn cứ cho rằng việc giải quyết tố cáo là không đúng pháp luật thì người tố cáo có quyền tố cáo tiếp với người đứng đầu cơ quan cấp trên trực tiếp của người có trách nhiệm giải quyết tố cáo."}, "11/01/2026": {"question": "Đồng chí cho biết, Luật tố cáo quy định về Trách nhiệm của cơ quan điều tra, Viện kiểm sát khi nhận được tố cáo hoặc hồ sơ vụ việc tố cáo có dấu hiệu tội phạm cụ thể như thế nào?", "answer": "Theo điều 28, Luật tố cáo quy định trách nhiệm của cơ quan điều tra, Viện kiểm sát khi nhận được tố cáo hoặc hồ sơ vụ việc tố cáo có dấu hiệu tội phạm như sau:\nTrong thời hạn 20 ngày, kể từ ngày nhận được tố cáo hoặc hồ sơ vụ việc tố cáo theo quy định tại khoản 3 Điều 20, khoản 3 Điều 25 của Luật này, cơ quan điều tra, Viện kiểm sát phải thông báo bằng văn bản về việc thụ lý, xử lý cho cơ quan, tổ chức chuyển tố cáo hoặc hồ sơ vụ việc tố cáo biết; trường hợp tố cáo có nội dung phức tạp thì thời hạn thông báo có thể kéo dài hơn, nhưng không quá 60 ngày."}, "12/01/2026": {"question": "Đồng chí cho biết, Luật tố cáo quy định về việc công khai kết luận nội dung tố cáo, và quyết định xử lý hành vi vi phạm bị tố cáo bằng hình thức nào?", "answer": "Người giải quyết tố cáo có trách nhiệm công khai kết luận nội dung tố cáo, quyết định xử lý hành vi vi phạm bị tố cáo bằng một trong các hình thức sau đây:\n- Công bố tại cuộc họp cơ quan, tổ chức nơi người bị tố cáo công tác;\n- Niêm yết tại trụ sở làm việc hoặc nơi tiếp công dân của cơ quan, tổ chức đã giải quyết tố cáo, quyết định xử lý hành vi vi phạm bị tố cáo;\n- Thông báo trên phương tiện thông tin đại chúng."}, "13/01/2026": {"question": "Đồng chí cho biết, Luật tố cáo quy định về phạm vi, đối tượng và thời hạn bảo vệ người tố cáo như thế nào?", "answer": "Theo điều 34. Luật tố cáo quy định phạm vi, đối tượng và thời hạn bảo vệ của người tố cáo cụ thể như sau:\n- Việc bảo vệ người tố cáo được thực hiện tại nơi cư trú, công tác, làm việc, học tập, nơi có tài sản của người cần được bảo vệ hoặc những nơi khác do cơ quan có thẩm quyền quyết định.\n- Đối tượng bảo vệ gồm có:\n+ Người tố cáo;\n+ Người thân thích của người tố cáo.\n- Thời hạn bảo vệ do cơ quan có thẩm quyền quyết định tùy thuộc vào tình hình thực tế của từng vụ việc, mức độ, tính chất của hành vi xâm phạm đến quyền và lợi ích hợp pháp của đối tượng cần được bảo vệ."}, "14/01/2026": {"question": "Đồng chí cho biết theo Luật tố cáo quy định các biện pháp bảo việ người tố cáo và người thân thích của họ như thế nào?", "answer": "Theo khoản 3, điểu 39 Luật tố cáo quy định các biện pháp sau đây: \n- Bố trí nơi tạm lánh khi người tố cáo, người thân thích của họ có nguy cơ bị xâm phạm đến tính mạng, sức khỏe;\n- Bố trí lực lượng, phương tiện, công cụ để trực tiếp bảo vệ an toàn tính mạng, sức khỏe, tài sản, danh dự, nhân phẩm, uy tín cho người tố cáo và người thân thích của họ tại nơi cần thiết;\n- Áp dụng biện pháp ngăn chặn, xử lý hành vi xâm hại hoặc đe dọa xâm hại đến tính mạng, sức khỏe, tài sản, danh dự, nhân phẩm, uy tín của người tố cáo và người thân thích của người tố cáo theo quy định của pháp luật;\n- Các biện pháp bảo vệ khác theo quy định của pháp luật."}, "15/01/2026": {"question": "Đồng chí cho biết theo Luật tố cáo quy định về trách nhiệm của cơ quan quản lý nhà nước về công tác giải quyết tố cáo?\nĐáp án: Theo điều 41, Luật tố cáo quy định Trách nhiệm của cơ quan quản lý nhà nước về công tác giải quyết tố cáo\n- Chính phủ thống nhất quản lý nhà nước về công tác giải quyết tố cáo trong các cơ quan hành chính nhà nước trong phạm vi cả nước.\n- Thanh tra Chính phủ chịu trách nhiệm trước Chính phủ thực hiện quản lý nhà nước về công tác giải quyết tố cáo trong phạm vi thẩm quyền của Chính phủ.\n- Thanh tra Bộ, cơ quan ngang Bộ, Thanh tra tỉnh, thành phố trực thuộc trung ương, Thanh tra sở, Thanh tra huyện, quận, thị xã, thành phố thuộc tỉnh giúp người đứng đầu cơ quan quản lý nhà nước cùng cấp quản lý công tác giải quyết tố cáo.\n\nNgày 16 tháng 01 năm 2026\nCâu hỏi:\nĐ/c cho biết theo Nghị định 171/2013/NĐ-CP của Chính phủ quy định về việc người điều khiển xe mô tô dưới 16 tuổi sẽ bị xử phạt như thế nào?", "answer": "Theo khoản 1, Điều 21 Nghị định 171/2013/NĐ-CP của Chính phủ quy định người điều khiển xe mô tô dưới 16 tuổi sẽ bị xử phạt Cảnh cáo."}, "17/01/2026": {"question": "Đ/c cho biết theo Nghị định 171/2013/NĐ-CP của Chính phủ quy định về việc người điều khiển xe mô tô từ 16 tuổi đến dưới 18 tuổi điều khiển xe mô tô từ 50cm3 trở lên sẽ bị xử phạt như thế nào?", "answer": "Theo điểm a, khoản 4, Điều 21 Nghị định 171/2013/NĐ-CP của Chính phủ quy định người điều khiển xe mô tô từ 16 tuổi đến dưới 18 tuổi điều khiển xe mô tô từ 50cm3 trở lên sẽ bị xử phạt từ 400.000 - 600.000đ"}, "18/01/2026": {"question": "Đ/c cho biết theo Nghị định 171/2013/NĐ-CP của Chính phủ quy định về việc người điều khiển xe mô tô dưới 175cm3 không có GPLX, sử dụng GPLX không do cơ quan có thẩm quyền cấp, GPLX hoặc bị tẩy xóa sẽ bị xử phạt như thế nào?", "answer": "Theo khoản 5, Điều 21 Nghị định 171/2013/NĐ-CP của Chính phủ quy định người điều khiển xe mô tô dưới 175cm3 không có GPLX, sử dụng GPLX không do cơ quan có thẩm quyền cấp, GPLX hoặc bị tẩy xóa sẽ bị xử phạt từ 800.000 - 1,2 triệu đồng; tịch thu GPLX không hợp lệ"}, "19/01/2026": {"question": "Đ/c cho biết theo Nghị định 171/2013/NĐ-CP của Chính phủ quy định về việc người điều khiển xe mô tô từ 175cm3 trở lên không có GPLX, sử dụng GPLX không do cơ quan có thẩm quyền cấp hoặc bị tẩy xóa sẽ bị xử phạt như thế nào?", "answer": "Theo điểm b, khoản 7, Điều 21 Nghị định 171/2013/NĐ-CP của Chính phủ quy định người điều khiển xe mô tô từ 175cm3 trở lên không có GPLX, sử dụng GPLX không do cơ quan có thẩm quyền cấp, GPLX hoặc bị tẩy xóa sẽ bị xử phạt từ 4 - 6 triệu đồng; tịch thu GPLX không hợp lệ."}, "20/01/2026": {"question": "Đ/c cho biết theo Nghị định 171/2013/NĐ-CP của Chính phủ quy định về việc người điều khiển xe mô tô từ 175cm3 trở lên có GPLX nhưng không phù hợp với loại xe đang điều khiển hoặc hết hạn sử dụng 6 tháng trở lên sẽ bị xử phạt như thế nào?", "answer": "Theo điểm a, khoản 7, Điều 21 Nghị định 171/2013/NĐ-CP của Chính phủ quy định người điều khiển xe mô tô từ175cm3 trở lên có GPLX nhưng không phù hợp với loại xe đang điều khiển hoặc hết hạn sử dụng 6 tháng trở lên sẽ bị xử phạt từ 4 - 6 triệu đồng;"}, "21/01/2026": {"question": "Đ/c cho biết theo Nghị định 171/2013/NĐ-CP của Chính phủ quy định về việc người điều khiển xe mô tô không mang theo Giấy phép lái xe sẽ bị xử phạt như thế nào?", "answer": "Theo điểm c, khoản 2, Điều 21 Nghị định 171/2013/NĐ-CP của Chính phủ quy định người điều khiển xe mô tô không mang theo Giấy phép lái xe sẽ bị xử phạt từ 80.000đ - 120.000đ."}, "22/01/2026": {"question": "Đ/c cho biết theo Nghị định 171/2013/NĐ-CP của Chính phủ quy định về việc người điều khiển xe mô tô không mang theo Giấy đăng ký xe sẽ bị xử phạt như thế nào?", "answer": "Theo điểm a, khoản 3, Điều 21 Nghị định 171/2013/NĐ-CP của Chính phủ quy định người điều khiển xe mô tô không mang theo Giấy đăng ký xe sẽ bị xử phạt từ 80.000đ - 120.000đ."}, "23/01/2026": {"question": "Đ/c cho biết theo Nghị định 171/2013/NĐ-CP của Chính phủ quy định về việc người điều khiển xe mô tô không có Giấy đăng ký xe sẽ bị xử phạt như thế nào?", "answer": "Theo điểm a, khoản 3, Điều 17 Nghị định 171/2013/NĐ-CP của Chính phủ quy định người điều khiển xe mô tô không có Giấy đăng ký xe sẽ bị xử phạt từ 300.000đ - 400.000đ"}, "24/01/2026": {"question": "Đ/c cho biết theo Nghị định 171/2013/NĐ-CP của Chính phủ quy định về việc người điều khiển xe mô tô sử dụng Giấy đăng ký xe bị tẩy xóa; không đúng số khung, số máy hoặc không do cơ quan có thẩm quyền cấp sẽ bị xử phạt như thế nào?", "answer": "Theo điểm b, khoản 3, Điều 17 Nghị định 171/2013/NĐ-CP của Chính phủ quy định người điều khiển xe mô tô sử dụng Giấy đăng ký xe bị tẩy xóa; không đúng số khung, số máy hoặc không do cơ quan có thẩm quyền cấp sẽ bị xử phạt từ 300.000đ - 400.000đ, tịch thu Giấy đăng ký không hợp lệ"}, "25/01/2026": {"question": "Đ/c cho biết theo Nghị định 171/2013/NĐ-CP của Chính phủ quy định về việc người điều khiển xe mô tô không có hoặc không mang theo Giấy chứng nhận bảo hiểm TNDS của chủ xe cơ giới sẽ bị xử phạt như thế nào?", "answer": "Theo điểm a, khoản 2, Điều 21 Nghị định 171/2013/NĐ-CP của Chính phủ quy định người điều khiển xe mô tô không có hoặc không mang theo Giấy chứng nhận bảo hiểm TNDS của chủ xe cơ giới sẽ bị xử phạt từ 80.000đ - 120.000đ."}, "26/01/2026": {"question": "Đ/c cho biết theo Nghị định 171/2013/NĐ-CP của Chính phủ quy định về việc người điều khiển xe mô tô chuyển làn đường không đúng nơi được phép hoặc không có tín hiệu báo trước sẽ bị xử phạt như thế nào?", "answer": "Theo điểm a, khoản 2, Điều 6 Nghị định 171/2013/NĐ-CP của Chính phủ quy định người điều khiển xe mô tô chuyển làn đường không đúng nơi được phép hoặc không có tín hiệu báo trước sẽ bị xử phạt từ 80.000đ - 100.000đ"}, "27/01/2026": {"question": "Đ/c cho biết theo Nghị định 171/2013/NĐ-CP của Chính phủ quy định về việc người điều khiển xe mô tô dừng xe, đỗ xe trên phần đường xe chạy ở đoạn đường ngoài đô thị nơi có lề đường sẽ bị kỷ luật như thế nào?", "answer": "Theo điểm a, khoản 3, Điều 6 Nghị định 171/2013/NĐ-CP của Chính phủ quy định người điều khiển xe mô tô dừng xe, đỗ xe trên phần đường xe chạy ở đoạn đường ngoài đô thị nơi có lề đường sẽ bị xử phạt từ 100.000 - 200.000đ (giữ GPLX 2 tháng nếu gây TNGT)"}, "28/01/2026": {"question": "Đ/c cho biết theo Nghị định 171/2013/NĐ-CP của Chính phủ quy định về việc người điều khiển xe mô tô dừng xe, đỗ xe ở lòng đường đô thị gây cản trở giao thông; đỗ, để xe ở lòng đường đô thị, hè phố trái quy định sẽ bị xử phạt như thế nào?", "answer": "Theo điểm đ, khoản 3, Điều 6 Nghị định 171/2013/NĐ-CP của Chính phủ quy định người điều khiển xe mô tô dừng xe, đỗ xe ở lòng đường đô thị gây cản trở giao thông; đỗ, để xe ở lòng đường đô thị, hè phố trái quy định sẽ bị xử phạt từ 100.000 - 200.000đ (giữ GPLX 2 tháng nếu gây TNGT)"}, "29/01/2026": {"question": "Đ/c cho biết theo Nghị định 171/2013/NĐ-CP của Chính phủ quy định về việc người điều khiển xe mô tô Chuyển hướng không giảm tốc độ hoặc không có tín hiệu báo hướng rẽ sẽ bị xử phạt như thế nào?", "answer": "Theo điểm a, khoản 4, Điều 6 Nghị định 171/2013/NĐ-CP của Chính phủ quy định người điều khiển xe mô tô Chuyển hướng không giảm tốc độ hoặc không có tín hiệu báo hướng rẽ sẽ bị xử phạt từ 200.000 - 400.000đ."}, "30/01/2026": {"question": "Đ/c cho biết theo Điều 2 Luật Tổ chức Chính phủ quy định cơ cấu tổ chức và thành viên của Chính phủ như thế nào?", "answer": "Theo 2 Luật Tổ chức Chính phủ quy định cơ cấu tổ chức và thành viên của Chính phủ:\n1. Chính phủ gồm Thủ tướng Chính phủ, các Phó Thủ tướng Chính phủ, các Bộ trưởng và Thủ trưởng cơ quan ngang bộ. Cơ cấu số lượng thành viên Chính phủ do Thủ tướng Chính phủ trình Quốc hội quyết định.\n2. Cơ cấu tổ chức của Chính phủ gồm các bộ, cơ quan ngang bộ."}, "31/01/2026": {"question": "Đ/c cho biết theo Điều 3 Luật Tổ chức Chính phủ quy định nhiệm kỳ của Chính phủ như thế nào?", "answer": "Theo Điều 3 Luật Tổ chức Chính phủ quy định Nhiệm kỳ của Chính phủ theo nhiệm kỳ của Quốc hội. Khi Quốc hội hết nhiệm kỳ, Chính phủ tiếp tục làm nhiệm vụ cho đến khi Quốc hội khóa mới thành lập Chính phủ."}, "01/02/2026": {"question": "Đ/c cho biết theo Điều 5 Luật Tổ chức Chính phủ quy định tổ chức và hoạt động của Chính phủ có bao nhiêu nguyên tắc?", "answer": "Theo Điều 5 Luật Tổ chức Chính phủ quy định tổ chức và hoạt động của Chính phủ có 5 nguyên tắc:\n1. Tuân thủ Hiến pháp và pháp luật, quản lý xã hội bằng Hiến pháp và pháp luật, thực hiện nguyên tắc tập trung dân chủ; bảo đảm bình đẳng giới.\n2. Phân định rõ nhiệm vụ, quyền hạn, trách nhiệm giữa Chính phủ, Thủ tướng Chính phủ với Bộ trưởng, Thủ trưởng cơ quan ngang bộ và chức năng, phạm vi quản lý giữa các bộ, cơ quan ngang bộ; đề cao trách nhiệm cá nhân của người đứng đầu.\n3. Tổ chức bộ máy hành chính tinh gọn, năng động, hiệu lực, hiệu quả; bảo đảm nguyên tắc cơ quan cấp dưới phục tùng sự lãnh đạo, chỉ đạo và chấp hành nghiêm chỉnh các quyết định của cơ quan cấp trên.\n4. Phân cấp, phân quyền hợp lý giữa Chính phủ với chính quyền địa phương, bảo đảm quyền quản lý thống nhất của Chính phủ và phát huy tính chủ động, sáng tạo, tự chịu trách nhiệm của chính quyền địa phương.\n5. Minh bạch, hiện đại hóa hoạt động của Chính phủ, các bộ, cơ quan ngang bộ, cơ quan hành chính nhà nước các cấp; bảo đảm thực hiện một nền hành chính thống nhất, thông suốt, liên tục, dân chủ, hiện đại, phục vụ Nhân dân, chịu sự kiểm tra, giám sát của Nhân dân."}, "02/02/2026": {"question": "Đ/c cho biết theo Điều 6 Luật Tổ chức Chính phủ quy định Chính phủ trong tổ chức thi hành Hiến pháp và pháp luật có bao nhiêu nhiệm vụ và quyền hạn?", "answer": "Theo Điều 6 Luật Tổ chức Chính phủ quy định Chính phủ trong tổ chức thi hành Hiến pháp và pháp luật có 4 nhiệm vụ và quyền hạn."}, "03/02/2026": {"question": "Đ/c cho biết theo Điều 7 Luật Tổ chức Chính phủ quy định Chính phủ trong hoạch định chính sách và trình dự án luật, pháp lệnh có bao nhiêu nhiệm vụ và quyền hạn?", "answer": "Theo Điều 7 Luật Tổ chức Chính phủ quy định Chính phủ trong hoạch định chính sách và trình dự án luật, pháp lệnh có 4 nhiệm vụ và quyền hạn."}, "04/02/2026": {"question": "Đ/c cho biết theo Điều 8 Luật Tổ chức Chính phủ quy định Chính phủ trong quản lý và phát triển kinh tế có bao nhiêu nhiệm vụ và quyền hạn?", "answer": "Theo Điều 8 Luật Tổ chức Chính phủ quy định Chính phủ trong quản lý và phát triển kinh tế có 8 nhiệm vụ và quyền hạn."}, "05/02/2026": {"question": "Đ/c cho biết theo Điều 9 Luật Tổ chức Chính phủ quy định Chính phủ trong quản lý tài nguyên, môi trường và ứng phó với biến đổi khí hậu có bao nhiêu nhiệm vụ và quyền hạn?", "answer": "Theo Điều 9 Luật Tổ chức Chính phủ quy định Chính phủ trong quản lý tài nguyên, môi trường và ứng phó với biến đổi khí hậu có 5 nhiệm vụ và quyền hạn."}, "06/02/2026": {"question": "Đ/c cho biết theo Điều 10 Luật Tổ chức Chính phủ quy định Chính phủ trong quản lý khoa học và công nghệ có bao nhiêu nhiệm vụ và quyền hạn?", "answer": "Theo Điều 10 Luật Tổ chức Chính phủ quy định Chính phủ trong quản lý khoa học và công nghệ có 5 nhiệm vụ và quyền hạn."}, "07/02/2026": {"question": "Đ/c cho biết theo Điều 11 Luật Tổ chức Chính phủ quy định Chính phủ trong giáo dục và đào tạo có bao nhiêu nhiệm vụ và quyền hạn?", "answer": "Theo Điều 11 Luật Tổ chức Chính phủ quy định Chính phủ trong giáo dục và đào tạo có 4 nhiệm vụ và quyền hạn."}, "08/02/2026": {"question": "Đ/c cho biết theo Điều 12 Luật Tổ chức Chính phủ quy định Chính phủ trong quản lý văn hóa, thể thao và du lịch có bao nhiêu nhiệm vụ và quyền hạn?", "answer": "Theo Điều 12 Luật Tổ chức Chính phủ quy định Chính phủ trong quản lý văn hóa, thể thao và du lịch có 4 nhiệm vụ và quyền hạn."}, "09/02/2026": {"question": "Đ/c cho biết theo Điều 13 Luật Tổ chức Chính phủ quy định Chính phủ trong quản lý thông tin và truyền thông có bao nhiêu nhiệm vụ và quyền hạn?", "answer": "Theo Điều 13 Luật Tổ chức Chính phủ quy định Chính phủ trong quản lý thông tin và truyền thông có 4 nhiệm vụ và quyền hạn."}, "10/02/2026": {"question": "Đ/c cho biết theo Điều 14 Luật Tổ chức Chính phủ quy định Chính phủ trong quản lý y tế, chăm sóc sức khỏe của Nhân dân và dân số có bao nhiêu nhiệm vụ và quyền hạn?", "answer": "Theo Điều 14 Luật Tổ chức Chính phủ quy định Chính phủ trong quản lý y tế, chăm sóc sức khỏe của Nhân dân và dân số có 5 nhiệm vụ và quyền hạn."}, "11/02/2026": {"question": "Đ/c cho biết theo Nghị định 171/2013/NĐ-CP của Chính phủ quy định về việc người điều khiển xe mô tô Chở theo 02 người trên xe, trừ trường hợp chở người bệnh đi cấp cứu, trẻ em dưới 14 tuổi sẽ bị xử phạt như thế nào?", "answer": "Theo điểm l, khoản 3, Điều 6 Nghị định 171/2013/NĐ-CP của Chính phủ quy định người điều khiển xe mô tô Chở theo 02 người trên xe, trừ trường hợp chở người bệnh đi cấp cứu, trẻ em dưới 14 tuổi sẽ bị xử phạt từ 100.000 - 200.000đ;"}, "12/02/2026": {"question": "Đ/c cho biết theo Nghị định 171/2013/NĐ-CP của Chính phủ quy định về việc người điều khiển xe mô tô Người điều khiển xe sử dụng điện thoại di động, thiết bị âm thanh sẽ bị xử phạt như thế nào?", "answer": "Theo điểm h, khoản 1, Điều 6 Nghị định 171/2013/NĐ-CP của Chính phủ quy định người điều khiển xe mô tô Người điều khiển xe sử dụng điện thoại di động, thiết bị âm thanh sẽ bị xử phạt từ 60.000 - 80.000đ; (giữ GPLX 2 tháng nếu gây TNGT)."}, "13/02/2026": {"question": "Đ/c cho biết theo Nghị định 171/2013/NĐ-CP của Chính phủ quy định về việc người điều khiển xe mô tô Không có gương chiếu hậu bên trái người điều khiển hoặc có nhưng không có tác dụng sẽ bị xử phạt như thế nào?", "answer": "Theo điểm a, khoản 1, Điều 17 Nghị định 171/2013/NĐ-CP của Chính phủ quy định người điều khiển xe mô tô Không có gương chiếu hậu bên trái người điều khiển hoặc có nhưng không có tác dụng sẽ bị xử phạt từ 80.000 - 100.000đ;"}, "14/02/2026": {"question": "Đ/c cho biết theo Nghị định 171/2013/NĐ-CP của Chính phủ quy định về việc người điều khiển xe mô tô Gắn biển số không đúng quy định; biển số không rõ chữ, số; biển số bị bẻ cong, bị hỏng sẽ bị xử phạt như thế nào?", "answer": "Theo điểm b, khoản 1, Điều 17 Nghị định 171/2013/NĐ-CP của Chính phủ quy định người điều khiển xe mô tô Gắn biển số không đúng quy định; biển số không rõ chữ, số; biển số bị bẻ cong, bị hỏng sẽ bị xử phạt từ 80.000 - 100.000đ;"}, "15/02/2026": {"question": "Đồng chí cho biết theo Luật khiếu nại quy định 05 hành vi bị cấm đầu tiên như thế nào?", "answer": "- Cản trở, gây phiền hà cho người thực hiện quyền khiếu nại; đe doạ, trả thù, trù dập người khiếu nại.\n- Thiếu trách nhiệm trong việc giải quyết khiếu nại; không giải quyết khiếu nại; làm sai lệch các thông tin, tài liệu, hồ sơ vụ việc khiếu nại; cố ý giải quyết khiếu nại trái pháp luật.\n- Ra quyết định giải quyết khiếu nại không bằng hình thức quyết định.\n- Bao che cho người bị khiếu nại; can thiệp trái pháp luật vào việc giải quyết khiếu nại.\n- Cố tình khiếu nại sai sự thật;"}, "16/02/2026": {"question": "Đồng chí cho biết, theo điểm 1, Điều 11 của Thông tư 143/TT-BQP, đối với Sĩ quan có mấy hình thức kỷ luật?\nĐáp án:  08\nKhiển trách; Cảnh cáo; Hạ bậc lương; Giáng chức; Cách chức; Giáng cấp bậc quân hàm; Tước quân hàm sĩ quan; Tước danh hiệu quân nhân.\nNgày 17 tháng 02 năm 2026\nCâu hỏi: \nĐồng chí cho biết, theo điểm 2, Điều 11 của Thông tư 143/TT-BQP, đối với QNCN có mấy hình thức kỷ luật?\nĐáp án:  07\n\tKhiển trách; Cảnh cáo; Hạ bậc lương; Giáng chức; Cách chức; Giáng cấp bậc quân hàm; Tước danh hiệu quân nhân.\nNgày 18 tháng 02 năm 2026\nCâu hỏi:\nĐồng chí cho biết, theo điểm 1, Điều 11 của Thông tư 143/TT-BQP, có mấy hình thức kỷ luật đối với hạ sĩ quan-binh sĩ?\nĐáp án: 06\n\tKhiển trách; Cảnh cáo; Giáng chức; Cách chức; Giáng cấp bậc quân hàm; Tước danh hiệu quân nhân.\nCâu hỏi:\nĐồng chí cho biết Thông tư 143/TT-BQP ban hành ngày, tháng năm nào gồm bao nhiêu chương, điều?", "answer": "Thông tư 143/TT-BQP ban hành ngày 27 tháng 12 năm 2023 gồm 5 chương 59 điều."}, "20/02/2026": {"question": "Đồng chí cho biết theo Chỉ thị số 04/CT-BQP Quy định mọi quân nhân phải thực hiện đúng lễ tiết tác phong khi ở trong và ngoài doanh trại như thế nào?", "answer": "Theo điểm 3 Chỉ thị số 04/CT-BQP Quy định mọi quân nhân phải thực hiện đúng lễ tiết tác phong khi ở trong và ngoài doanh trại như sau:\nMọi quân nhân phải thực hiện đúng lễ tiết tác phong khi ở trong và ngoài doanh trại: Quân nhân khi đi đứng, xưng hô, chào hỏi, phải đúng điều lệnh, mang mặc trang phục phải đúng quy định. Khi đi tập thể từ 3 người trở lên phải đi thành đội ngũ và có người chỉ huy. Cấm quân nhân mặc quân phục ăn, uống rượu bia ở hàng quán vỉa hè."}, "22/02/2026": {"question": "Đồng chí cho biết Chỉ thị 22-CT/TM, ngày 05/7/2019 của Bộ Tổng Tham mưu Quân đội nhân dân Việt Nam, nói về vấn đề gì? Gồm mấy nội dung?", "answer": "- Chỉ thị số 22/CT-TM, ngày 05/7/2019 của Bộ Tổng Tham mưu Quân đội nhân dân Việt Nam về việc tăng cường một số biện pháp trong công tác giáo dục, quản lý chấp hành pháp luật Nhà nước, kỷ luật Quân đội và bảo đảm an toàn trong QĐND Việt Nam.\n- Gồm có 7 nội dung"}, "23/02/2026": {"question": "Đồng chí cho biết nội dung thứ 2 của Chỉ thị 22-CT/TM, ngày 05/7/2019 của Bộ Tổng Tham mưu Quân đội nhân dân Việt Nam, nói về vấn đề gì?", "answer": "Nội dung thứ 2: Từng cơ quan, đơn vị duy trì nghiêm kỷ cương, kỷ luật\n        \t- Quản lý chặt chẽ số lượng, chất lượng quân nhân, vũ khí, khí tài trang bị, duy trì và thực hiện nghiêm các chế độ nền nếp sinh hoạt chính quy trong ngày, tuần, tháng theo quy định, đơn vị có kỷ cương, kỷ luật;\n        \t- Mọi quân nhân thuộc và thực hiện nghiêm 10 Lời thề danh dự của quân nhân, 12 Điều kỷ luật trong quan hệ với nhân dân và chức trách, nhiệm vụ, chế độ công tác trên cương vị được giao; chống biểu hiện vô ý thức tổ chức, kỷ luật, tự do, tùy tiện\n        \t- Tăng cường đổi mới công tác kiểm tra, đánh giá đúng thực chất tình hình đơn vị; tổ chức rút kinh nghiệm khắc phục kịp thời những thiếu sót, khuyết điểm; xử lý nghiêm minh, công bằng các hành vi, vi phạm pháp luật, kỷ luật, vi phạm quy tắc, quy định đảm bảo an toàn đúng tính chất, mức độ vi phạm. Nghiêm cấm việc bao che, giấu diếm khuyết điểm của tổ chức, cá nhân vi phạm với bất kỳ động cơ nào."}, "24/02/2026": {"question": "Đồng chí cho biết theo Luật khiếu nại quy định 04 hành vi bị cấm cuối cùng như thế nào?", "answer": "- Kích động, xúi giục, cưỡng ép, dụ dỗ, mua chuộc, lôi kéo người khác tập trung đông người khiếu nại, gây rối an ninh trật tự công cộng.\n- Lợi dụng việc khiếu nại để tuyên truyền chống Nhà nước, xâm phạm lợi ích của Nhà nước; xuyên tạc, vu khống, đe dọa, xúc phạm uy tín, danh dự của cơ quan, tổ chức, người có trách nhiệm giải quyết khiếu nại, người thi hành nhiệm vụ, công vụ khác.\n- Vi phạm quy chế tiếp công dân;\n- Vi phạm các quy định khác của pháp luật về khiếu nại và giải quyết khiếu nại."}, "25/02/2026": {"question": "Đ/c cho biết theo quy định thời gian bảo quản VKTBKT khí tài hàng tuần là bao nhiêu phút?", "answer": "Theo quy định thời gian bảo quản VKTBKT khí tài hàng tuần là: VKTB bảo quản 30 phút, VKTBKT khác, khí tài phức tạp bảo quản từ 3 đến 4 giờ, thời gian bảo quản vào ngày làm việc cuối tuần."}, "26/02/2026": {"question": "Đồng chí cho biết theo Luật Khiếu nại quy định hình thức khiếu nại bằng đơn phải thực hiện như thế nào?", "answer": "Theo khoản 2, điều 8, Luật khiếu nại quy định: Trường hợp khiếu nại được thực hiện bằng đơn thì trong đơn khiếu nại phải ghi rõ ngày, tháng, năm khiếu nại; tên, địa chỉ của người khiếu nại; tên, địa chỉ của cơ quan, tổ chức, cá nhân bị khiếu nại; nội dung, lý do khiếu nại, tài liệu liên quan đến nội dung khiếu nại và yêu cầu giải quyết của người khiếu nại. Đơn khiếu nại phải do người khiếu nại ký tên hoặc điểm chỉ."}, "27/02/2026": {"question": "Đồng chí cho biết theo Luật Khiếu nại quy định hình thức khiếu nại trực tiếp phải thực hiện như thế nào?", "answer": "Theo khoản 2, điều 8, Luật khiếu nại quy định: Trường hợp người khiếu nại đến khiếu nại trực tiếp thì người tiếp nhận khiếu nại hướng dẫn người khiếu nại viết đơn khiếu nại hoặc người tiếp nhận ghi lại việc khiếu nại bằng văn bản và yêu cầu người khiếu nại ký hoặc điểm chỉ xác nhận vào văn bản, trong đó ghi rõ nội dung theo quy định tại khoản 2."}, "28/02/2026": {"question": "Đồng chí cho biết nội dung thứ 3 của Chỉ thị 22-CT/TM, ngày 05/7/2019 của Bộ Tổng Tham mưu Quân đội nhân dân Việt Nam, nói về vấn đề gì? \nĐáp án: Nội dung thứ 3: Bảo đảm an toàn trong huấn luyện\n        \t- Chấp hành nghiêm quy tắc, quy định bảo đảm an toàn trong huấn luyện;\n         \t- Huấn luyện có sử dụng vũ khí, khí tài, đạn, thuốc nổ, xe máy…Cơ quan kỹ thuật phải kiểm tra, xử lý triệt để, bảo đảm vũ khí, khí tài, đạn, thuốc nổ         \t- Quân nhân có bệnh tim mạch, thần kinh không cho tham gia huấn luyện bơi, vượt sông và các nội dung huấn luyện thể lực cường độ cao;\n         \t- Không được tùy ý sửa đổi, điều khiển, cắt xén kế hoạch huấn luyện khi chưa có ý kiến của cấp phê duyệt (cả nội dung, thời gian, biện pháp huấn luyện)\nNgày 01 tháng 3 năm 2026\nCâu hỏi:\nĐồng chí cho biết nội dung thứ 4 của Chỉ thị 22-CT/TM, ngày 05/7/2019 của Bộ Tổng Tham mưu Quân đội nhân dân Việt Nam, nói về vấn đề gì?", "answer": "Nội dung thứ 4: Bảo dảm an toàn khi tham gia giao thông \n         \t- Tiếp tục quán triệt, thực hiện nghiêm Chỉ thị số 25/CT-TM ngày 12/5/2003 của Tổng Tham mưu trưởng “Về việc quản lý, sử dụng xe mô tô, xe gắn máy trong Quân đội”;\n        \t- Trong các ngày nghỉ, giờ nghỉ cấp tiểu đoàn, đại đội và tương đương xây dựng kế hoạch hoạt động, vui chơi giải trí; cấp trung, lữ đoàn định kỳ hàng tháng, quý tổ chức hội thao giao lưu VHVN, TDTT… (tùy điều kiện nhiệm vụ cụ thể để tổ chức cho phù hợp, hiệu quả); giải quyết quân nhân ra ngoài doanh trại đúng quy định; \n        \t- Thực hiện nghiêm quy định về quản lý, sử dụng phương tiện vận tải quân sự. Nghiêm cấm sử dụng xe không có thiết kế ghế ngồi, xe tự đổ (xe ben), xe không có mui, bạt để chở quân (trừ xe nghỉ lễ, xe chuyên dụng);\n        \t- Quân nhân khi tham gia giao thông bằng xe mô tô, xe gắn máy phải đội mũ bảo hiểm đúng quy chuẩn. Trên mũ: bên phải ghi rõ họ tên người sử dụng; bên trái ghi tên cơ quan, đơn vị mình và trên một cấp. Không điều khiển phương tiện tham gia giao thông khi đã sử dụng rượu, bia, chất kích thích;\n        \t- Khi có vụ việc mất an toàn xảy ra, chỉ huy cơ quan, đơn vị để xảy ra vụ việc phối hợp chặt chẽ với các cơ quan chức năng, địa phương, gia đình giải quyết hậu quả, không để kéo dài, gây dư luận xấu."}, "02/03/2026": {"question": "Đồng chí cho biết điểm 2, Điều 4 Thông tư 143/TT-BQP quy định như thế nào?", "answer": "Theo điểm 2, Điều 4 Thông tư 143/TT-BQP quy định như sau:\n\tViệc xử lý vi phạm kỷ luật được tiến hành nhanh chóng, chính xác, công khai, khách quan, đúng thẩm quyền, bảo đảm công bằng, đúng quy định của pháp luật."}, "03/03/2026": {"question": "Đồng chí cho biết điểm 1, Điều 5 Thông tư 143/TT- BQP quy định như thế nào?", "answer": "1. Tình tiết giảm nhẹ:\n\ta) Người vi phạm kỷ luật đã có hành vi ngăn chặn, làm giảm bớt hậu quả của vi phạm hoặc tự nguyện khắc phục hậu quả, bồi thường thiệt hại;\n\tb) Người vi phạm kỷ luật đã tự nguyện khai báo, thành thật hối lỗi, tích cực giúp đỡ cơ quan chức năng phát hiện vi phạm, xử lý vi phạm kỷ luật;\n\tc) Vi phạm kỷ luật do bị ép buộc hoặc bị lệ thuộc về vật chất hoặc tinh thần; vi phạm trong hoàn cảnh đặc biệt khó khăn."}, "04/03/2026": {"question": "Đồng chí cho biết điểm 2, Điều 5 Thông tư 143/TT- BQP quy định như thế nào?", "answer": "Theo điểm 2, Điều 5 Thông tư 143/TT- BQP quy định như sau:\n\t2. Tình tiết tăng nặng:\n\ta) Vi phạm kỷ luật nhiều lần hoặc tái phạm;\n\tb) Ép buộc người bị lệ thuộc vào mình về vật chất hoặc tinh thần thực hiện hành vi vi phạm kỷ luật;\n\tc) Lợi dụng chức vụ, quyền hạn để vi phạm kỷ luật;\n\td) Tiếp tục vi phạm kỷ luật mặc dù người có thẩm quyền đã yêu cầu chấm dứt hành vi vi phạm đó;\n\tđ) Sau khi vi phạm kỷ luật đã có hành vi trốn tránh, che giấu vi phạm kỷ luật"}, "05/03/2026": {"question": "Đồng chí cho biết Điểm 1, Điều 7 Thông tư 143/TT-BQP của Bộ Quốc phòng quy định như thế nào?", "answer": "1. Trường hợp người vi phạm kỷ luật không đồng ý với quyết định xử lý kỷ luật thì có quyền khiếu nại đến cơ quan, đơn vị có thẩm quyền theo quy định của pháp luật và Bộ Quốc phòng.\n\tKhi chưa có quyết định giải quyết của cấp có thẩm quyền, người vi phạm kỷ luật vẫn phải chấp hành nghiêm quyết định hiện hành."}, "06/03/2026": {"question": "Đ/c cho biết, quân nhân khi phát biểu trong hội nghị và nghi lễ Quân Đội tại bục phát biểu phải thực hiện đúng động tác chào đơn vị trước và sau khi phát biểu được quy định như thế nào?", "answer": "Quân nhân khi phát biểu trong hội nghị và nghi lễ Quân đội tại bục phát biểu phải thực hiện đúng động tác chào đơn vị trước và sau khi phát biểu được quy định như sau: Chỉ thực hiện ở phần phát biểu đầu tiên, các phần phát biểu sau không phải thực hiện động tác chào."}, "07/03/2026": {"question": "Đồng chí cho biết theo Luật Khiếu nại quy định thời hiệu khiếu nại cụ thể như thế nào?", "answer": "Theo điều 9, Luật khiếu nại quy định: Thời hiệu khiếu nại là 90 ngày, kể từ ngày nhận được quyết định hành chính hoặc biết được quyết định hành chính, hành vi hành chính.\nTrường hợp người khiếu nại không thực hiện được quyền khiếu nại theo đúng thời hiệu vì ốm đau, thiên tai, địch họa, đi công tác, học tập ở nơi xa hoặc vì những trở ngại khách quan khác thì thời gian có trở ngại đó không tính vào thời hiệu khiếu nại."}, "08/03/2026": {"question": "Đồng chí cho biết nội dung thứ 5 của Chỉ thị 22-CT/TM, ngày 05/7/2019 của Bộ Tổng Tham mưu Quân đội nhân dân Việt Nam, nói về vấn đề gì?", "answer": "Nọi dung thứ 5: Bảo đảm an toàn trong đóng quân canh phòng\n        \t- Trong khu vực đóng quân phải có biển cấm, biển báo những nơi nguy hiểm như đường hẹp, đường quanh co, sập, đổ, sạt lở, điện giật, đuối nước… những thời điểm cần thiết phải tổ chức canh gác ngăn ngừa;\n       \t- Tổ chức tuần tra, canh gác chặt chẽ bảo vệ an toàn các mục tiêu, tính mạng, tài sản, trang bị và duy trì kỷ luật, trật tự khu vực đóng quân theo đúng quy định của công tác đóng quân canh phòng;\n       \t- Quân nhân trong cơ quan, đơn vị khi qua cổng phải có giấy ra vào; khách tới cơ quan, đơn vị phải có giấy giới thiệu liên hệ công tác và giấy tờ tùy thân (chứng minh thư, thẻ căn cước) phải đăng ký nội dung công việc, người giải quyết. Khi được sự đồng ý của người có thẩm quyền mới cho vào. Cơ quan, đơn vị có khách phải cử người ra đón."}, "09/03/2026": {"question": "Đồng chí cho biết theo Luật Khiếu nại quy định về nghĩa vụ của người bị khiếu nại như thế nào?", "answer": "Theo khoản 2, điều 13, Luật khiếu nại quy định Người bị khiếu nại có nghĩa vụ như sau :\n- Tham gia đối thoại hoặc ủy quyền cho người đại diện hợp pháp tham gia đối thoại; Chấp hành quyết định xác minh nội dung khiếu nại của cơ quan, đơn vị có thẩm quyền giải quyết khiếu nại;\n- Cung cấp thông tin, tài liệu liên quan đến nội dung khiếu nại, giải trình về tính hợp pháp, đúng đắn của quyết định hành chính, hành vi hành chính bị khiếu nại khi người giải quyết khiếu nại hoặc cơ quan, đơn vị kiểm tra, xác minh yêu cầu trong thời hạn 7 ngày, kể từ ngày có yêu cầu;\n- Chấp hành nghiêm chỉnh quyết định giải quyết khiếu nại đã có hiệu lực pháp luật; Sửa đổi hoặc hủy bỏ quyết định hành chính, chấm dứt hành vi hành chính bị khiếu nại; Bồi thường, bồi hoàn thiệt hại do quyết định hành chính, hành vi hành chính trái pháp luật của mình gây ra theo quy định của pháp luật về trách nhiệm bồi thường của Nhà nước."}, "10/03/2026": {"question": "Đồng chí cho biết nội dung thứ 6 của Chỉ thị 22-CT/TM, ngày 05/7/2019 của Bộ Tổng Tham mưu Quân đội nhân dân Việt Nam, nói về vấn đề gì?", "answer": "Nội dung thứ 6: Quản lý, sử dụng phương tiện thông tin liên lạc di động cá nhân\n       \t- Các cơ quan, đơn vị trong toàn quân tiếp tục quán triệt và thực hiện nghiêm túc Pháp lệnh Bảo vệ bí mật Nhà nước số 30/2000/PL-UBTVQH10 ngày 28/12/2000; Thông tư số 202/20143/TT-BQP ngày 12/12/20143 của Bộ Quốc phòng quy định về bảo đảm an toàn thông tin trong QĐNDVN và Chỉ thị số 02/CT-BQP ngày 29/01/20143 của Bộ trưởng Bộ Quốc phòng về việc tăng cường công tác quản lý việc sử dụng thiết bị ghi âm, ghi hình trong Quân đội.\n       \t- Căn cứ vào nhiệm vụ, tình hình cụ thể, các cơ quan, đơn vị, học viện, trường có quy định về việc quản lý, sử dụng phương tiện thông tin liên lạc di động của cá nhân đối tượng tới nhiệm vụ chung của đơn vị, bảo đảm chấp hành nghiêm kỷ luật an ninh mạng, pháp lệnh bảo vệ bí mật Nhà nước, điều lệ bí mật chỉ huy và các chỉ thị quy định bí mật trong Quân đội."}, "11/03/2026": {"question": "Đồng chí cho biết Chỉ thị số 103/CT-BQP, ngày 28/11/2019 của Bộ trưởng Bộ Quốc phòng nói về vấn đề gì?", "answer": "Chỉ thị số 103/CT-BQP, ngày 28/11/2019 của Bộ trưởng Bộ Quốc phòng về việc tiếp tục tăng cường quản lý, giáo dục chấp hành kỷ luật và bảo đảm an toàn trong Quân đội nhân dân Việt Nam"}, "12/03/2026": {"question": "Đồng chí cho biết Chỉ thị số 103/CT-BQP, ngày 28/11/2019 của Bộ trưởng Bộ Quốc phòng gồm có mấy nội dung?", "answer": "Gồm có 6 nội dung"}, "13/03/2026": {"question": "Đồng chí cho biết theo Luật Khiếu nại quy định về thẩm quyền giải quyết khiếu nại của Chủ tịch Ủy ban nhân dân xã, phường, thị trấn như thế nào?", "answer": "Theo điều 17, Luật khiếu nại quy định: Chủ tịch Ủy ban nhân dân xã, phường, thị trấn (sau đây gọi chung là cấp xã); có thẩm quyền giải quyết khiếu nại lần đầu đối với quyết định hành chính, hành vi hành chính của mình, của người có trách nhiệm do mình quản lý trực tiếp."}, "15/03/2026": {"question": "Đồng chí cho biết theo Luật Khiếu nại quy định về thẩm quyền giải quyết khiếu nại của Thủ trưởng cơ quan thuộc sở và cấp tương đương như thế nào?", "answer": "Theo điều 19, Luật khiếu nại quy định, thẩm quyền giải quyết khiếu nại của Thủ trưởng cơ quan thuộc sở và cấp tương đương như sau:\nThủ trưởng cơ quan thuộc sở và cấp tương đương có thẩm quyền giải quyết khiếu nại lần đầu đối với quyết định hành chính, hành vi hành chính của mình, của cán bộ, công chức do mình quản lý trực tiếp."}, "16/03/2026": {"question": "Đồng chí cho biết theo Luật Khiếu nại quy định về thẩm quyền giải quyết khiếu nại của giám đốc sở và cấp tương đương như thế nào?", "answer": "Theo điều 20, Luật khiếu nại quy định, thẩm quyền giải quyết khiếu nại của giám đốc sở và cấp tương đương như sau:\n- Giải quyết khiếu nại lần đầu đối với quyết định hành chính, hành vi hành chính của mình, của cán bộ, công chức do mình quản lý trực tiếp;\n- Giải quyết khiếu nại lần hai đối với quyết định hành chính, hành vi hành chính của Thủ trưởng cơ quan thuộc sở và cấp tương đương đã giải quyết lần đầu nhưng còn khiếu nại hoặc khiếu nại lần đầu đã hết thời hạn nhưng chưa được giải quyết."}, "17/03/2026": {"question": "Đồng chí cho biết theo Luật Khiếu nại quy định về thẩm quyền giải quyết khiếu nại của Chủ tịch Ủy ban nhân dân cấp tỉnh như thế nào?", "answer": "Theo điều 21, Luật khiếu nại quy định, thẩm quyền giải quyết khiếu nại của Chủ tịch Ủy ban nhân dân cấp tỉnh như sau:\n- Giải quyết khiếu nại lần đầu đối với quyết định hành chính, hành vi hành chính của mình.\n- Giải quyết khiếu nại lần hai đối với quyết định hành chính, hành vi hành chính của Chủ tịch Ủy ban nhân dân cấp huyện, Giám đốc sở và cấp tương đương đã giải quyết lần đầu nhưng còn khiếu nại hoặc khiếu nại lần đầu đã hết thời hạn nhưng chưa được giải quyết.\n- Giải quyết tranh chấp về thẩm quyền giải quyết khiếu nại giữa các cơ quan, đơn vị thuộc phạm vi quản lý của mình."}, "18/03/2026": {"question": "Đồng chí cho biết nội dung thứ 3 của Chỉ thị số 103/CT-BQP, ngày 28/11/2019 của Bộ trưởng Bộ Quốc phòng?", "answer": "Chỉ huy các cấp phải quản lý kỷ luật toàn diện đối với mọi cấp, mọi nghành, mọi đơn vị; mọi lúc, mọi nơi, mọi hoàn cảnh. Đặc biệt cán Bộ phải làm gương cho chiến sĩ; cấp trên phải làm gương cho cấp dưới, cơ quan phải làm gương cho đơn vị; chiến sĩ cũ làm gương cho chiến sĩ mới; Đảng viên phải làm gương cho quần chúng cả về lời nói và việc làm; Giữ nghiêm kỷ luật đối với việc chấp hành pháp luật nhà nước, điều lệnh, điều lệnh, nguyên tắc, chế độ quy định của Quân đội; Quy tắc sinh hoạt xã hội, quan hệ quân dân, quân hệ quân nhân; kết hợp chặt chẽ giữa giáo dục với kiên quyết xử lí kịp thời, đúng quy định đối với quân nhân có thái độ, hành vi vi phạm những cán bộ quản lí, lãnh đạo, chỉ huy không làm tròn chức trách, nhiệm vụ để quân nhân, đơn vị thuộc quyền vi phạm pháp luật, kỷ luật."}, "19/03/2026": {"question": "Đồng chí cho biết theo điểm 1, Điều 3 Luật Xử lý vi phạm hành chính năm 2020, có bao nhiêu nguyên tắc xử phạt vi phạm hành chính?", "answer": "Theo điểm 1, Điều 3 Luật Xử lý vi phạm hành chính năm 2020, có 6 nguyên tắc xử phạt vi phạm hành chính."}, "20/03/2026": {"question": "Đồng chí cho biết theo điểm 2, Điều 3 Luật Xử lý vi phạm hành chính năm 2020, có bao nhiêu nguyên tắc áp dụng các biện pháp xử lý hành chính?", "answer": "Theo điểm 2, Điều 3 Luật Xử lý vi phạm hành chính sửa đổi bổ sung năm 2020, có 4 nguyên tắc áp dụng các biện pháp xử lý hành chính."}, "21/03/2026": {"question": "Đồng chí cho biết theo điểm 1, Điều 5 Luật Xử lý vi phạm hành chính năm 2020, có bao nhiêu đối tượng bị xử phạt vi phạm hành chính?", "answer": "Theo điểm 1, Điều 5 Luật Xử lý vi phạm hành chính năm 2020, có 3 đối tượng bị xử phạt vi phạm hành chính."}, "22/03/2026": {"question": "Đồng chí cho biết theo Điều 9 Luật Xử lý vi phạm hành chính năm 2020, có bao nhiêu tình tiết giảm nhẹ?\nĐáp án:Theo Điều 9 Luật Xử lý vi phạm hành chính năm 2020, có 8 tình tiết giảm nhẹ.\nNgày 24 tháng 3 năm 2026\nCâu hỏi:\nĐồng chí cho biết theo điểm 1, Điều 10 Luật Xử lý vi phạm hành chính năm 2020, có bao nhiêu tình tiết tăng nặng?", "answer": "Theo điểm 1, Điều 10 Luật Xử lý vi phạm hành chính năm 2020, có 12 tình tiết tăng nặng."}, "25/03/2026": {"question": "Đồng chí cho biết Luật Tố cáo có bao nhiêu chương, bao nhiêu điều và có hiệu lực thi hành từ ngày tháng năm nào?", "answer": "Luật tố cáo có 8 chương, 50 điều, và có hiệu lực thi hành từ ngày 01/7/2020."}, "26/03/2026": {"question": "Đồng chí cho biết Luật khiếu nại có bao nhiêu chương, bao nhiêu điều và có hiệu lực thi hành từ ngày tháng năm nào?", "answer": "Luật khiếu nại có 8 chương, 70 điều, và có hiệu lực thi hành từ ngày 01/7/2020."}, "27/03/2026": {"question": "Đồng chí cho biết theo Luật tố cáo quy định 07 hành vi bị cấm đầu tiên như thế nào?", "answer": "- Gây khó khăn, phiền hà đối với việc thực hiện quyền tố cáo của công dân.\n- Thiếu trách nhiệm trong việc giải quyết tố cáo.\n- Tiết lộ họ, tên, địa chỉ, bút tích của người tố cáo và những thông tin khác có thể làm lộ danh tính của người tố cáo.\n- Làm sai lệch hồ sơ vụ việc trong quá trình giải quyết tố cáo.\n- Không giải quyết hoặc cố ý giải quyết tố cáo trái pháp luật; lợi dụng chức vụ, quyền hạn trong việc giải quyết tố cáo để thực hiện hành vi trái pháp luật, sách nhiễu, gây phiền hà cho người bị tố cáo.\n- Không thực hiện hoặc thực hiện không đầy đủ trách nhiệm bảo vệ người tố cáo.\n- Cản trở, can thiệp trái pháp luật vào việc giải quyết tố cáo."}, "28/03/2026": {"question": "Đồng chí cho biết theo Luật tố cáo quy định 07 hành vi bị cấm cuối cùng như thế nào?", "answer": "- Cản trở việc thực hiện quyền tố cáo; đe doạ, trả thù, trù dập, xúc phạm người tố cáo.\n- Bao che người bị tố cáo.\n- Cố ý tố cáo sai sự thật; kích động, cưỡng ép, dụ dỗ, mua chuộc người khác tố cáo sai sự thật; mạo danh người khác để tố cáo.\n- Mua chuộc, hối lộ người giải quyết tố cáo; đe doạ, trả thù, xúc phạm người giải quyết tố cáo.\n- Lợi dụng việc tố cáo để tuyên truyền chống Nhà nước, xâm phạm lợi ích của Nhà nước; xuyên tạc, vu khống, gây rối an ninh, trật tự công cộng, xúc phạm danh dự, nhân phẩm, uy tín của người khác.\n- Đưa tin sai sự thật về việc tố cáo và giải quyết tố cáo.\n- Vi phạm các quy định khác của pháp luật về tố cáo và giải quyết tố cáo."}, "29/03/2026": {"question": "Đồng chí cho biết theo điều 9 Luật tố cáo quy định người tố cáo có quyền như thế nào?", "answer": "Theo điều 9 Luật tố cáo, Người tố cáo có các quyền sau đây:\n- Gửi đơn hoặc trực tiếp tố cáo với cơ quan, tổ chức, cá nhân có thẩm quyền theo quy định của pháp luật;\n- Được giữ bí mật họ, tên, địa chỉ, bút tích và các thông tin cá nhân khác của mình;\n- Yêu cầu cơ quan, tổ chức, cá nhân có thẩm quyền thông báo về việc thụ lý giải quyết tố cáo, thông báo chuyển vụ việc tố cáo sang cơ quan có thẩm quyền giải quyết, thông báo kết quả giải quyết tố cáo;\n- Tố cáo tiếp khi có căn cứ cho rằng việc giải quyết tố cáo của cơ quan, tổ chức, cá nhân có thẩm quyền không đúng pháp luật hoặc quá thời hạn quy định mà tố cáo không được giải quyết;\n- Yêu cầu cơ quan, tổ chức, cá nhân có thẩm quyền bảo vệ khi bị đe dọa, trả thù, trù dập;\n- Được khen thưởng theo quy định của pháp luật."}, "30/03/2026": {"question": "Đồng chí cho biết theo Điều 9 Luật tố cáo quy định người tố cáo có nghĩa vụ như thế nào?", "answer": "Theo điều 9 Luật tố cáo, Người tố cáo có các nghĩa vụ sau đây:\n- Nêu rõ họ, tên, địa chỉ của mình;\n- Trình bày trung thực về nội dung tố cáo; cung cấp thông tin, tài liệu liên quan đến nội dung tố cáo mà mình có được;\n- Chịu trách nhiệm trước pháp luật về nội dung tố cáo của mình;\n- Bồi thường thiệt hại do hành vi cố ý tố cáo sai sự thật của mình gây ra."}, "31/03/2026": {"question": "Đồng chí cho biết theo điều 10, Luật tố cáo quy định người bị tố cáo có quyền như thế nào?", "answer": "Theo điều 10 Luật tố cáo, Người bị tố cáo có các quyền sau đây:\n- Được thông báo về nội dung tố cáo;\n- Đưa ra chứng cứ để chứng minh nội dung tố cáo là không đúng sự thật;\n- Nhận thông báo kết luận nội dung tố cáo;\n- Yêu cầu cơ quan, tổ chức, cá nhân có thẩm quyền xử lý người cố ý tố cáo sai sự thật, người cố ý giải quyết tố cáo trái pháp luật;\n- Được khôi phục quyền, lợi ích hợp pháp bị xâm phạm, được xin lỗi, cải chính công khai, được bồi thường thiệt hại do việc tố cáo, giải quyết tố cáo không đúng gây ra."}, "01/04/2026": {"question": "Đồng chí cho biết theo điều 10, Luật tố cáo quy định người bị tố cáo có nghĩa vụ như thế nào?", "answer": "Theo điều 10 Luật tố cáo, Người bị tố cáo có các nghĩa vụ sau đây:\n- Giải trình bằng văn bản về hành vi bị tố cáo; cung cấp thông tin, tài liệu liên quan khi cơ quan, tổ chức, cá nhân có thẩm quyền yêu cầu;\n- Chấp hành nghiêm chỉnh quyết định xử lý của cơ quan, tổ chức, cá nhân có thẩm quyền;\n- Bồi thường, bồi hoàn thiệt hại do hành vi trái pháp luật của mình gây ra."}, "02/04/2026": {"question": "Đồng chí cho biết theo điều 11, Luật tố cáo quy định người giải quyết tố cáo có quyền như thế nào?", "answer": "Theo điều 11 Luật tố cáo, Người giải quyết tố cáo có các quyền sau đây:\n- Yêu cầu người tố cáo cung cấp thông tin, tài liệu liên quan đến nội dung tố cáo;\n- Yêu cầu người bị tố cáo giải trình bằng văn bản về hành vi bị tố cáo;\n- Yêu cầu cơ quan, tổ chức, cá nhân cung cấp thông tin, tài liệu liên quan đến nội dung tố cáo;\n- Tiến hành các biện pháp kiểm tra, xác minh, thu thập chứng cứ để giải quyết tố cáo theo quy định của pháp luật; áp dụng các biện pháp theo thẩm quyền để ngăn chặn, chấm dứt hành vi vi phạm pháp luật;\n- Kết luận về nội dung tố cáo;\n- Quyết định xử lý theo thẩm quyền hoặc kiến nghị cơ quan, tổ chức, cá nhân có thẩm quyền xử lý theo quy định của pháp luật."}, "03/04/2026": {"question": "Đồng chí cho biết theo điều 11, Luật tố cáo quy định người giải quyết tố cáo có nghĩa vụ như thế nào?", "answer": "- Bảo đảm khách quan, trung thực, đúng pháp luật trong việc giải quyết tố cáo;\n- Áp dụng các biện pháp cần thiết theo thẩm quyền hoặc yêu cầu cơ quan chức năng áp dụng các biện pháp để bảo vệ người tố cáo, người thân thích của người tố cáo, người cung cấp thông tin có liên quan đến việc tố cáo;\n- Không tiết lộ thông tin gây bất lợi cho người bị tố cáo khi chưa có kết luận về nội dung tố cáo;\n- Chịu trách nhiệm trước pháp luật về việc giải quyết tố cáo;\n- Bồi thường, bồi hoàn thiệt hại do hành vi giải quyết tố cáo trái pháp luật của mình gây ra."}, "04/04/2026": {"question": "Đồng chí cho biết theo Luật tố cáo quy định trình tự giải quyết tố cáo như thế nào?", "answer": "Theo điều 18, Luật tố cáo quy định trình tự giải quyết tố cáo như sau:\n1. Tiếp nhận, xử lý thông tin tố cáo;\n2. Xác minh nội dung tố cáo;\n3. Kết luận nội dung tố cáo;\n4. Xử lý tố cáo của người giải quyết tố cáo;\n5. Công khai kết luận nội dung tố cáo, quyết định xử lý hành vi vi phạm bị tố cáo."}, "05/04/2026": {"question": "Đồng chí cho biết Chỉ thị 22-CT/TM, ngày 05/7/2019 của Bộ Tổng Tham mưu Quân đội nhân dân Việt Nam, nói về vấn đề gì? Gồm mấy nội dung?", "answer": "- Chỉ thị số 22/CT-TM, ngày 05/7/2019 của Bộ Tổng Tham mưu Quân đội nhân dân Việt Nam về việc tăng cường một số biện pháp trong công tác giáo dục, quản lý chấp hành pháp luật Nhà nước, kỷ luật Quân đội và bảo đảm an toàn trong QĐND Việt Nam.\n- Gồm có 7 nội dung"}, "06/04/2026": {"question": "Đồng chí cho biết nội dung thứ 2 của Chỉ thị 22-CT/TM, ngày 05/7/2019 của Bộ Tổng Tham mưu Quân đội nhân dân Việt Nam, nói về vấn đề gì?", "answer": "Nội dung thứ 2: Từng cơ quan, đơn vị duy trì nghiêm kỷ cương, kỷ luật\n        \t- Quản lý chặt chẽ số lượng, chất lượng quân nhân, vũ khí, khí tài trang bị, duy trì và thực hiện nghiêm các chế độ nền nếp sinh hoạt chính quy trong ngày, tuần, tháng theo quy định, đơn vị có kỷ cương, kỷ luật;\n        \t- Mọi quân nhân thuộc và thực hiện nghiêm 10 Lời thề danh dự của quân nhân, 12 Điều kỷ luật trong quan hệ với nhân dân và chức trách, nhiệm vụ, chế độ công tác trên cương vị được giao; chống biểu hiện vô ý thức tổ chức, kỷ luật, tự do, tùy tiện\n        \t- Tăng cường đổi mới công tác kiểm tra, đánh giá đúng thực chất tình hình đơn vị; tổ chức rút kinh nghiệm khắc phục kịp thời những thiếu sót, khuyết điểm; xử lý nghiêm minh, công bằng các hành vi, vi phạm pháp luật, kỷ luật, vi phạm quy tắc, quy định đảm bảo an toàn đúng tính chất, mức độ vi phạm. Nghiêm cấm việc bao che, giấu diếm khuyết điểm của tổ chức, cá nhân vi phạm với bất kỳ động cơ nào."}, "07/04/2026": {"question": "Đồng chí cho biết theo Luật khiếu nại quy định 04 hành vi bị cấm cuối cùng như thế nào?", "answer": "- Kích động, xúi giục, cưỡng ép, dụ dỗ, mua chuộc, lôi kéo người khác tập trung đông người khiếu nại, gây rối an ninh trật tự công cộng.\n- Lợi dụng việc khiếu nại để tuyên truyền chống Nhà nước, xâm phạm lợi ích của Nhà nước; xuyên tạc, vu khống, đe dọa, xúc phạm uy tín, danh dự của cơ quan, tổ chức, người có trách nhiệm giải quyết khiếu nại, người thi hành nhiệm vụ, công vụ khác.\n- Vi phạm quy chế tiếp công dân;\n- Vi phạm các quy định khác của pháp luật về khiếu nại và giải quyết khiếu nại."}, "08/04/2026": {"question": "Đ/c cho biết theo quy định thời gian bảo quản VKTBKT khí tài hàng tuần là bao nhiêu phút?", "answer": "Theo quy định thời gian bảo quản VKTBKT khí tài hàng tuần là: VKTB bảo quản 30 phút, VKTBKT khác, khí tài phức tạp bảo quản từ 3 đến 4 giờ, thời gian bảo quản vào ngày làm việc cuối tuần."}, "09/04/2026": {"question": "Đồng chí cho biết theo Luật Khiếu nại quy định hình thức khiếu nại bằng đơn phải thực hiện như thế nào?", "answer": "Theo khoản 2, điều 8, Luật khiếu nại quy định: Trường hợp khiếu nại được thực hiện bằng đơn thì trong đơn khiếu nại phải ghi rõ ngày, tháng, năm khiếu nại; tên, địa chỉ của người khiếu nại; tên, địa chỉ của cơ quan, tổ chức, cá nhân bị khiếu nại; nội dung, lý do khiếu nại, tài liệu liên quan đến nội dung khiếu nại và yêu cầu giải quyết của người khiếu nại. Đơn khiếu nại phải do người khiếu nại ký tên hoặc điểm chỉ."}, "10/04/2026": {"question": "Đồng chí cho biết theo Luật Khiếu nại quy định hình thức khiếu nại trực tiếp phải thực hiện như thế nào?", "answer": "Theo khoản 2, điều 8, Luật khiếu nại quy định: Trường hợp người khiếu nại đến khiếu nại trực tiếp thì người tiếp nhận khiếu nại hướng dẫn người khiếu nại viết đơn khiếu nại hoặc người tiếp nhận ghi lại việc khiếu nại bằng văn bản và yêu cầu người khiếu nại ký hoặc điểm chỉ xác nhận vào văn bản, trong đó ghi rõ nội dung theo quy định tại khoản 2."}, "11/04/2026": {"question": "Đồng chí cho biết nội dung thứ 3 của Chỉ thị 22-CT/TM, ngày 05/7/2019 của Bộ Tổng Tham mưu Quân đội nhân dân Việt Nam, nói về vấn đề gì? \nĐáp án: Nội dung thứ 3: Bảo đảm an toàn trong huấn luyện\n        \t- Chấp hành nghiêm quy tắc, quy định bảo đảm an toàn trong huấn luyện;\n         \t- Huấn luyện có sử dụng vũ khí, khí tài, đạn, thuốc nổ, xe máy…Cơ quan kỹ thuật phải kiểm tra, xử lý triệt để, bảo đảm vũ khí, khí tài, đạn, thuốc nổ         \t- Quân nhân có bệnh tim mạch, thần kinh không cho tham gia huấn luyện bơi, vượt sông và các nội dung huấn luyện thể lực cường độ cao;\n         \t- Không được tùy ý sửa đổi, điều khiển, cắt xén kế hoạch huấn luyện khi chưa có ý kiến của cấp phê duyệt (cả nội dung, thời gian, biện pháp huấn luyện)\nNgày 12 tháng 4 năm 2026\nCâu hỏi:\nĐồng chí cho biết nội dung thứ 4 của Chỉ thị 22-CT/TM, ngày 05/7/2019 của Bộ Tổng Tham mưu Quân đội nhân dân Việt Nam, nói về vấn đề gì?", "answer": "Nội dung thứ 4: Bảo dảm an toàn khi tham gia giao thông \n         \t- Tiếp tục quán triệt, thực hiện nghiêm Chỉ thị số 25/CT-TM ngày 12/5/2003 của Tổng Tham mưu trưởng “Về việc quản lý, sử dụng xe mô tô, xe gắn máy trong Quân đội”;\n        \t- Trong các ngày nghỉ, giờ nghỉ cấp tiểu đoàn, đại đội và tương đương xây dựng kế hoạch hoạt động, vui chơi giải trí; cấp trung, lữ đoàn định kỳ hàng tháng, quý tổ chức hội thao giao lưu VHVN, TDTT… (tùy điều kiện nhiệm vụ cụ thể để tổ chức cho phù hợp, hiệu quả); giải quyết quân nhân ra ngoài doanh trại đúng quy định; \n        \t- Thực hiện nghiêm quy định về quản lý, sử dụng phương tiện vận tải quân sự. Nghiêm cấm sử dụng xe không có thiết kế ghế ngồi, xe tự đổ (xe ben), xe không có mui, bạt để chở quân (trừ xe nghỉ lễ, xe chuyên dụng);\n        \t- Quân nhân khi tham gia giao thông bằng xe mô tô, xe gắn máy phải đội mũ bảo hiểm đúng quy chuẩn. Trên mũ: bên phải ghi rõ họ tên người sử dụng; bên trái ghi tên cơ quan, đơn vị mình và trên một cấp. Không điều khiển phương tiện tham gia giao thông khi đã sử dụng rượu, bia, chất kích thích;\n        \t- Khi có vụ việc mất an toàn xảy ra, chỉ huy cơ quan, đơn vị để xảy ra vụ việc phối hợp chặt chẽ với các cơ quan chức năng, địa phương, gia đình giải quyết hậu quả, không để kéo dài, gây dư luận xấu."}, "13/04/2026": {"question": "Đồng chí cho biết điểm 2, Điều 4 Thông tư 143/TT-BQP quy định như thế nào?", "answer": "Theo điểm 2, Điều 4 Thông tư 143/TT-BQP quy định như sau:\n\tViệc xử lý vi phạm kỷ luật được tiến hành nhanh chóng, chính xác, công khai, khách quan, đúng thẩm quyền, bảo đảm công bằng, đúng quy định của pháp luật."}, "14/04/2026": {"question": "Đồng chí cho biết điểm 1, Điều 5 Thông tư 143/TT- BQP quy định như thế nào?", "answer": "1. Tình tiết giảm nhẹ:\n\ta) Người vi phạm kỷ luật đã có hành vi ngăn chặn, làm giảm bớt hậu quả của vi phạm hoặc tự nguyện khắc phục hậu quả, bồi thường thiệt hại;\n\tb) Người vi phạm kỷ luật đã tự nguyện khai báo, thành thật hối lỗi, tích cực giúp đỡ cơ quan chức năng phát hiện vi phạm, xử lý vi phạm kỷ luật;\n\tc) Vi phạm kỷ luật do bị ép buộc hoặc bị lệ thuộc về vật chất hoặc tinh thần; vi phạm trong hoàn cảnh đặc biệt khó khăn."}, "15/04/2026": {"question": "Đồng chí cho biết điểm 2, Điều 5 Thông tư 143/TT- BQP quy định như thế nào?", "answer": "Theo điểm 2, Điều 5 Thông tư 143/TT- BQP quy định như sau:\n\t2. Tình tiết tăng nặng:\n\ta) Vi phạm kỷ luật nhiều lần hoặc tái phạm;\n\tb) Ép buộc người bị lệ thuộc vào mình về vật chất hoặc tinh thần thực hiện hành vi vi phạm kỷ luật;\n\tc) Lợi dụng chức vụ, quyền hạn để vi phạm kỷ luật;\n\td) Tiếp tục vi phạm kỷ luật mặc dù người có thẩm quyền đã yêu cầu chấm dứt hành vi vi phạm đó;\n\tđ) Sau khi vi phạm kỷ luật đã có hành vi trốn tránh, che giấu vi phạm kỷ luật"}, "16/04/2026": {"question": "Đồng chí cho biết Điểm 1, Điều 7 Thông tư 143/TT-BQP của Bộ Quốc phòng quy định như thế nào?", "answer": "1. Trường hợp người vi phạm kỷ luật không đồng ý với quyết định xử lý kỷ luật thì có quyền khiếu nại đến cơ quan, đơn vị có thẩm quyền theo quy định của pháp luật và Bộ Quốc phòng.\n\tKhi chưa có quyết định giải quyết của cấp có thẩm quyền, người vi phạm kỷ luật vẫn phải chấp hành nghiêm quyết định hiện hành."}, "17/04/2026": {"question": "Đồng chí cho biết theo điểm 1, Điều 10, Thông tư 143/TT-BQP quy định có mấy hình thức kỷ luật đối với sĩ quan, quân nhân chuyên nghiệp?", "answer": "Theo điểm 1, Điều 10, Thông tư 143/TT-BQP quy định có 8 hình thức kỷ luật đối với sĩ quan, quân nhân chuyên nghiệp"}, "18/04/2026": {"question": "Đ/c cho biết, quân nhân khi phát biểu trong hội nghị và nghi lễ Quân Đội tại bục phát biểu phải thực hiện đúng động tác chào đơn vị trước và sau khi phát biểu được quy định như thế nào?", "answer": "Quân nhân khi phát biểu trong hội nghị và nghi lễ Quân đội tại bục phát biểu phải thực hiện đúng động tác chào đơn vị trước và sau khi phát biểu được quy định như sau: Chỉ thực hiện ở phần phát biểu đầu tiên, các phần phát biểu sau không phải thực hiện động tác chào."}, "19/04/2026": {"question": "Đồng chí cho biết Nghị định 100/2019/NĐ-CP quy định về xử phạt vi phạm hành chính trong lĩnh vực giao thông đường bộ và đường sắt gồm mấy chương, mấy điều?", "answer": "Gồm 5 chương, 86 điều."}, "20/04/2026": {"question": "Đồng chí cho biết, các biện pháp khắc phục hậu quả vi phạm hành chính trong lĩnh vực giao thông đường bộ, đường sắt?", "answer": "Theo  Điều 4, chương I  của Nghị định 100/2019/NĐ-CP, có 6 biện pháp:\n- Buộc khôi phục lại tình trạng ban đầu đã bị thay đổi do vi phạm hành chính gây ra;\n- Buộc tháo dỡ công trình, phần công trình xây dựng không có giấy phép hoặc xây dựng không đúng với giấy phép;\n- Buộc thực hiện biện pháp để khắc phục tình trạng ô nhiễm môi trường do vi phạm hành chính gây ra;"}, "21/04/2026": {"question": "Đồng chí cho biết, theo Điều 5, mục 1, chương II của Nghị định 100/2019/NĐ-CP, người tham gia giao thông khi dừng xe, đỗ xe không có tín hiệu báo cho người điều khiển phương tiện khác biết thì bị phạt tiền như thế nào?", "answer": "Theo Điểm 1, khoản 1, Điều 5, mục 1, chương II của Nghị định 100/2019/NĐ-CP  bị phạt tiền từ 200.000 đồng đến 400.000 đồng."}, "22/04/2026": {"question": "Đồng chí cho biết, theo Điều 5, mục 1, chương II của Nghị định 100/2019/NĐ-CP, người tham gia giao thông chở người trên buồng lái quá số lượng quy định thì bị phạt như thế nào?", "answer": "Theo Điểm 1, khoản 2, Điều 5, mục 1, chương II của Nghị định 100/2019/NĐ-CP bị Phạt tiền từ 400.000 đồng đến 600.000 đồng"}, "23/04/2026": {"question": "Đồng chí cho biết, theo Điều 5, mục 1, chương II của Nghị định 100/2019/NĐ-CP, người tham gia giao thông điều khiển xe chạy quá tốc độ quy định từ 05 km/h đến dưới 10 km/h thì bị phạt như thế nào?", "answer": "Theo Điểm 1, khoản 3, Điều 5, mục 1, chương II của Nghị định 100/2019/NĐ-CP bị phạt tiền từ 800.000 đồng đến 1.000.000 đồng."}, "24/04/2026": {"question": "Đồng chí cho biết, theo Điều 5, mục 1, chương II của Nghị định 100/2019/NĐ-CP, người tham gia giao thông dùng tay sử dụng điện thoại di động khi đang điều khiển xe chạy trên đường thì bị phạt như thế nào?", "answer": "Theo Điểm 1, khoản 4, Điều 5, mục 1, chương II của Nghị định 100/2019/NĐ-CP bị phạt tiền từ 1.000.000 đồng đến 2.000.000 đồng ."}, "25/04/2026": {"question": "Đồng chí cho biết, theo Điều 5, mục 1, chương II của Nghị định 100/2019/NĐ-CP, người tham gia giao thông không chấp hành hiệu lệnh của đèn tín hiệu giao thông thì bị phạt như thế nào?", "answer": "Theo Điểm 1, khoản 5, Điều 5, mục 1, chương II của Nghị định 100/2019/NĐ-CP bị phạt tiền từ 3.000.000 đồng đến 5.000.000 đồng."}, "26/04/2026": {"question": "Đồng chí cho biết, theo Điều 5, mục 1, chương II của Nghị định 100/2019/NĐ-CP, người tham gia giao thông điều khiển xe chạy quá tốc độ quy định trên 20 km/h đến 35 km/h thì bị phạt như thế nào?", "answer": "Theo Điểm 1, khoản 6, Điều 5, mục 1, chương II của Nghị định 100/2019/NĐ-CP bị phạt tiền từ 6.000.000 đồng đến 8.000.000 đồng."}, "27/04/2026": {"question": "Đồng chí cho biết, theo Điều 5, mục 1, chương II của Nghị định 100/2019/NĐ-CP, người tham gia giao thông điều khiển xe lạng lách, đánh võng; chạy quá tốc độ đuổi nhau trên đường bộ; dùng chân điều khiển vô lăng xe khi xe đang chạy trên đường thì bị phạt như thế nào?", "answer": "Theo Điểm 1, khoản 7, Điều 5, mục 1, chương II của Nghị định 100/2019/NĐ-CP bị phạt tiền 10.000.000 đồng đến 12.000.000 đồng ."}, "28/04/2026": {"question": "Đồng chí cho biết, theo Điều 5, mục 1, chương II của Nghị định 100/2019/NĐ-CP, người tham gia giao thông gây tai nạn giao thông không dừng lại, không giữ nguyên hiện trường, bỏ trốn không đến trình báo với cơ quan có thẩm quyền, không tham gia cấp cứu người bị nạn thì bị phạt như thế nào?", "answer": "Theo Điểm 1, khoản 8, Điều 5, mục 1, chương II của Nghị định 100/2019/NĐ-CP bị phạt tiền từ 16.000.000 đồng đến 18.000.000 đồng."}, "29/04/2026": {"question": "Đồng chí cho biết theo Luật Khiếu nại quy định thời hiệu khiếu nại cụ thể như thế nào?", "answer": "Theo điều 9, Luật khiếu nại quy định: Thời hiệu khiếu nại là 90 ngày, kể từ ngày nhận được quyết định hành chính hoặc biết được quyết định hành chính, hành vi hành chính.\nTrường hợp người khiếu nại không thực hiện được quyền khiếu nại theo đúng thời hiệu vì ốm đau, thiên tai, địch họa, đi công tác, học tập ở nơi xa hoặc vì những trở ngại khách quan khác thì thời gian có trở ngại đó không tính vào thời hiệu khiếu nại."}, "30/04/2026": {"question": "Đồng chí cho biết nội dung thứ 5 của Chỉ thị 22-CT/TM, ngày 05/7/2019 của Bộ Tổng Tham mưu Quân đội nhân dân Việt Nam, nói về vấn đề gì?", "answer": "Nội dung thứ 5: Bảo đảm an toàn trong đóng quân canh phòng\n        \t- Trong khu vực đóng quân phải có biển cấm, biển báo những nơi nguy hiểm như đường hẹp, đường quanh co, sập, đổ, sạt lở, điện giật, đuối nước… những thời điểm cần thiết phải tổ chức canh gác ngăn ngừa;\n       \t- Tổ chức tuần tra, canh gác chặt chẽ bảo vệ an toàn các mục tiêu, tính mạng, tài sản, trang bị và duy trì kỷ luật, trật tự khu vực đóng quân theo đúng quy định của công tác đóng quân canh phòng;\n       \t- Quân nhân trong cơ quan, đơn vị khi qua cổng phải có giấy ra vào; khách tới cơ quan, đơn vị phải có giấy giới thiệu liên hệ công tác và giấy tờ tùy thân (chứng minh thư, thẻ căn cước) phải đăng ký nội dung công việc, người giải quyết. Khi được sự đồng ý của người có thẩm quyền mới cho vào. Cơ quan, đơn vị có khách phải cử người ra đón."}, "01/05/2026": {"question": "Đồng chí cho biết theo Luật Khiếu nại quy định về nghĩa vụ của người bị khiếu nại như thế nào?", "answer": "Theo khoản 2, điều 13, Luật khiếu nại quy định Người bị khiếu nại có nghĩa vụ như sau :\n- Tham gia đối thoại hoặc ủy quyền cho người đại diện hợp pháp tham gia đối thoại; Chấp hành quyết định xác minh nội dung khiếu nại của cơ quan, đơn vị có thẩm quyền giải quyết khiếu nại;\n- Cung cấp thông tin, tài liệu liên quan đến nội dung khiếu nại, giải trình về tính hợp pháp, đúng đắn của quyết định hành chính, hành vi hành chính bị khiếu nại khi người giải quyết khiếu nại hoặc cơ quan, đơn vị kiểm tra, xác minh yêu cầu trong thời hạn 7 ngày, kể từ ngày có yêu cầu;\n- Chấp hành nghiêm chỉnh quyết định giải quyết khiếu nại đã có hiệu lực pháp luật; Sửa đổi hoặc hủy bỏ quyết định hành chính, chấm dứt hành vi hành chính bị khiếu nại; Bồi thường, bồi hoàn thiệt hại do quyết định hành chính, hành vi hành chính trái pháp luật của mình gây ra theo quy định của pháp luật về trách nhiệm bồi thường của Nhà nước."}, "02/05/2026": {"question": "Đồng chí cho biết nội dung thứ 6 của Chỉ thị 22-CT/TM, ngày 05/7/2019 của Bộ Tổng Tham mưu Quân đội nhân dân Việt Nam, nói về vấn đề gì?", "answer": "Nội dung thứ 6: Quản lý, sử dụng phương tiện thông tin liên lạc di động cá nhân\n       \t- Các cơ quan, đơn vị trong toàn quân tiếp tục quán triệt và thực hiện nghiêm túc Pháp lệnh Bảo vệ bí mật Nhà nước số 30/2000/PL-UBTVQH10 ngày 28/12/2000; Thông tư số 202/2016/TT-BQP ngày 12/12/2016 của Bộ Quốc phòng quy định về bảo đảm an toàn thông tin trong QĐNDVN và Chỉ thị số 02/CT-BQP ngày 29/01/2016 của Bộ trưởng Bộ Quốc phòng về việc tăng cường công tác quản lý việc sử dụng thiết bị ghi âm, ghi hình trong Quân đội.\n       \t- Căn cứ vào nhiệm vụ, tình hình cụ thể, các cơ quan, đơn vị, học viện, trường có quy định về việc quản lý, sử dụng phương tiện thông tin liên lạc di động của cá nhân đối tượng tới nhiệm vụ chung của đơn vị, bảo đảm chấp hành nghiêm kỷ luật an ninh mạng, pháp lệnh bảo vệ bí mật Nhà nước, điều lệ bí mật chỉ huy và các chỉ thị quy định bí mật trong Quân đội."}, "03/05/2026": {"question": "Đồng chí cho biết Chỉ thị số 103/CT-BQP, ngày 28/11/2019 của Bộ trưởng Bộ Quốc phòng nói về vấn đề gì?", "answer": "Chỉ thị số 103/CT-BQP, ngày 28/11/2019 của Bộ trưởng Bộ Quốc phòng về việc tiếp tục tăng cường quản lý, giáo dục chấp hành kỷ luật và bảo đảm an toàn trong Quân đội nhân dân Việt Nam"}, "04/05/2026": {"question": "Đồng chí cho biết Chỉ thị số 103/CT-BQP, ngày 28/11/2019 của Bộ trưởng Bộ Quốc phòng gồm có mấy nội dung?", "answer": "Gồm có 6 nội dung"}, "05/05/2026": {"question": "Đồng chí cho biết theo Luật Khiếu nại quy định về thẩm quyền giải quyết khiếu nại của Chủ tịch Ủy ban nhân dân xã, phường, thị trấn như thế nào?", "answer": "Theo điều 17, Luật khiếu nại quy định: Chủ tịch Ủy ban nhân dân xã, phường, thị trấn (sau đây gọi chung là cấp xã); có thẩm quyền giải quyết khiếu nại lần đầu đối với quyết định hành chính, hành vi hành chính của mình, của người có trách nhiệm do mình quản lý trực tiếp."}, "07/05/2026": {"question": "Đồng chí cho biết theo Luật Khiếu nại quy định về thẩm quyền giải quyết khiếu nại của Thủ trưởng cơ quan thuộc sở và cấp tương đương như thế nào?", "answer": "Theo điều 19, Luật khiếu nại quy định, thẩm quyền giải quyết khiếu nại của Thủ trưởng cơ quan thuộc sở và cấp tương đương như sau:\nThủ trưởng cơ quan thuộc sở và cấp tương đương có thẩm quyền giải quyết khiếu nại lần đầu đối với quyết định hành chính, hành vi hành chính của mình, của cán bộ, công chức do mình quản lý trực tiếp."}, "08/05/2026": {"question": "Đồng chí cho biết theo Luật Khiếu nại quy định về thẩm quyền giải quyết khiếu nại của giám đốc sở và cấp tương đương như thế nào?", "answer": "Theo điều 20, Luật khiếu nại quy định, thẩm quyền giải quyết khiếu nại của giám đốc sở và cấp tương đương như sau:\n- Giải quyết khiếu nại lần đầu đối với quyết định hành chính, hành vi hành chính của mình, của cán bộ, công chức do mình quản lý trực tiếp;\n- Giải quyết khiếu nại lần hai đối với quyết định hành chính, hành vi hành chính của Thủ trưởng cơ quan thuộc sở và cấp tương đương đã giải quyết lần đầu nhưng còn khiếu nại hoặc khiếu nại lần đầu đã hết thời hạn nhưng chưa được giải quyết."}, "09/05/2026": {"question": "Đồng chí cho biết theo Luật Khiếu nại quy định về thẩm quyền giải quyết khiếu nại của Chủ tịch Ủy ban nhân dân cấp tỉnh như thế nào?", "answer": "Theo điều 21, Luật khiếu nại quy định, thẩm quyền giải quyết khiếu nại của Chủ tịch Ủy ban nhân dân cấp tỉnh như sau:\n- Giải quyết khiếu nại lần đầu đối với quyết định hành chính, hành vi hành chính của mình.\n- Giải quyết khiếu nại lần hai đối với quyết định hành chính, hành vi hành chính của Chủ tịch Ủy ban nhân dân cấp huyện, Giám đốc sở và cấp tương đương đã giải quyết lần đầu nhưng còn khiếu nại hoặc khiếu nại lần đầu đã hết thời hạn nhưng chưa được giải quyết.\n- Giải quyết tranh chấp về thẩm quyền giải quyết khiếu nại giữa các cơ quan, đơn vị thuộc phạm vi quản lý của mình."}, "10/05/2026": {"question": "Đồng chí cho biết nội dung thứ 3 của Chỉ thị số 103/CT-BQP, ngày 28/11/2019 của Bộ trưởng Bộ Quốc phòng?", "answer": "Chỉ huy các cấp phải quản lý kỷ luật toàn diện đối với mọi cấp, mọi nghành, mọi đơn vị; mọi lúc, mọi nơi, mọi hoàn cảnh. Đặc biệt cán Bộ phải làm gương cho chiến sĩ; cấp trên phải làm gương cho cấp dưới, cơ quan phải làm gương cho đơn vị; chiến sĩ cũ làm gương cho chiến sĩ mới; Đảng viên phải làm gương cho quần chúng cả về lời nói và việc làm; Giữ nghiêm kỷ luật đối với việc chấp hành pháp luật nhà nước, điều lệnh, điều lệnh, nguyên tắc, chế độ quy định của Quân đội; Quy tắc sinh hoạt xã hội, quan hệ quân dân, quân hệ quân nhân; kết hợp chặt chẽ giữa giáo dục với kiên quyết xử lí kịp thời, đúng quy định đối với quân nhân có thái độ, hành vi vi phạm những cán bộ quản lí, lãnh đạo, chỉ huy không làm tròn chức trách, nhiệm vụ để quân nhân, đơn vị thuộc quyền vi phạm pháp luật, kỷ luật."}, "11/05/2026": {"question": "Đồng chí cho biết theo điểm 1, Điều 3 Luật Xử lý vi phạm hành chính năm 2020, có bao nhiêu nguyên tắc xử phạt vi phạm hành chính?", "answer": "Theo điểm 1, Điều 3 Luật Xử lý vi phạm hành chính năm 2020, có 6 nguyên tắc xử phạt vi phạm hành chính."}, "12/05/2026": {"question": "Đồng chí cho biết theo điểm 2, Điều 3 Luật Xử lý vi phạm hành chính năm 2020, có bao nhiêu nguyên tắc áp dụng các biện pháp xử lý hành chính?", "answer": "Theo điểm 2, Điều 3 Luật Xử lý vi phạm hành chính sửa đổi bổ sung năm 2020, có 4 nguyên tắc áp dụng các biện pháp xử lý hành chính."}, "13/05/2026": {"question": "Đồng chí cho biết theo điểm 1, Điều 5 Luật Xử lý vi phạm hành chính năm 2020, có bao nhiêu đối tượng bị xử phạt vi phạm hành chính?", "answer": "Theo điểm 1, Điều 5 Luật Xử lý vi phạm hành chính năm 2020, có 3 đối tượng bị xử phạt vi phạm hành chính."}, "14/05/2026": {"question": "Đồng chí cho biết theo Điều 9 Luật Xử lý vi phạm hành chính năm 2020, có bao nhiêu tình tiết giảm nhẹ?\nĐáp án:Theo Điều 9 Luật Xử lý vi phạm hành chính năm 2020, có 8 tình tiết giảm nhẹ.\nNgày 15 tháng 5 năm 2026\nCâu hỏi:\nĐồng chí cho biết theo điểm 1, Điều 10 Luật Xử lý vi phạm hành chính năm 2020, có bao nhiêu tình tiết tăng nặng?", "answer": "Theo điểm 1, Điều 10 Luật Xử lý vi phạm hành chính năm 2020, có 12 tình tiết tăng nặng."}, "16/05/2026": {"question": "Đồng chí cho biết Luật Tố cáo có bao nhiêu chương, bao nhiêu điều và có hiệu lực thi hành từ ngày tháng năm nào?", "answer": "Luật tố cáo có 8 chương, 50 điều, và có hiệu lực thi hành từ ngày 01/7/2020."}, "17/05/2026": {"question": "Đồng chí cho biết Luật khiếu nại có bao nhiêu chương, bao nhiêu điều và có hiệu lực thi hành từ ngày tháng năm nào?", "answer": "Luật khiếu nại có 8 chương, 70 điều, và có hiệu lực thi hành từ ngày 01/7/2020."}, "18/05/2026": {"question": "Đồng chí cho biết theo Luật tố cáo quy định 07 hành vi bị cấm đầu tiên như thế nào?", "answer": "- Gây khó khăn, phiền hà đối với việc thực hiện quyền tố cáo của công dân.\n- Thiếu trách nhiệm trong việc giải quyết tố cáo.\n- Tiết lộ họ, tên, địa chỉ, bút tích của người tố cáo và những thông tin khác có thể làm lộ danh tính của người tố cáo.\n- Làm sai lệch hồ sơ vụ việc trong quá trình giải quyết tố cáo.\n- Không giải quyết hoặc cố ý giải quyết tố cáo trái pháp luật; lợi dụng chức vụ, quyền hạn trong việc giải quyết tố cáo để thực hiện hành vi trái pháp luật, sách nhiễu, gây phiền hà cho người bị tố cáo.\n- Không thực hiện hoặc thực hiện không đầy đủ trách nhiệm bảo vệ người tố cáo.\n- Cản trở, can thiệp trái pháp luật vào việc giải quyết tố cáo."}, "19/05/2026": {"question": "Đồng chí cho biết theo Luật tố cáo quy định 07 hành vi bị cấm cuối cùng như thế nào?", "answer": "- Cản trở việc thực hiện quyền tố cáo; đe doạ, trả thù, trù dập, xúc phạm người tố cáo.\n- Bao che người bị tố cáo.\n- Cố ý tố cáo sai sự thật; kích động, cưỡng ép, dụ dỗ, mua chuộc người khác tố cáo sai sự thật; mạo danh người khác để tố cáo.\n- Mua chuộc, hối lộ người giải quyết tố cáo; đe doạ, trả thù, xúc phạm người giải quyết tố cáo.\n- Lợi dụng việc tố cáo để tuyên truyền chống Nhà nước, xâm phạm lợi ích của Nhà nước; xuyên tạc, vu khống, gây rối an ninh, trật tự công cộng, xúc phạm danh dự, nhân phẩm, uy tín của người khác.\n- Đưa tin sai sự thật về việc tố cáo và giải quyết tố cáo.\n- Vi phạm các quy định khác của pháp luật về tố cáo và giải quyết tố cáo."}, "20/05/2026": {"question": "Đồng chí cho biết theo điều 9 Luật tố cáo quy định người tố cáo có quyền như thế nào?", "answer": "Theo điều 9 Luật tố cáo, Người tố cáo có các quyền sau đây:\n- Gửi đơn hoặc trực tiếp tố cáo với cơ quan, tổ chức, cá nhân có thẩm quyền theo quy định của pháp luật;\n- Được giữ bí mật họ, tên, địa chỉ, bút tích và các thông tin cá nhân khác của mình;\n- Yêu cầu cơ quan, tổ chức, cá nhân có thẩm quyền thông báo về việc thụ lý giải quyết tố cáo, thông báo chuyển vụ việc tố cáo sang cơ quan có thẩm quyền giải quyết, thông báo kết quả giải quyết tố cáo;\n- Tố cáo tiếp khi có căn cứ cho rằng việc giải quyết tố cáo của cơ quan, tổ chức, cá nhân có thẩm quyền không đúng pháp luật hoặc quá thời hạn quy định mà tố cáo không được giải quyết;\n- Yêu cầu cơ quan, tổ chức, cá nhân có thẩm quyền bảo vệ khi bị đe dọa, trả thù, trù dập;\n- Được khen thưởng theo quy định của pháp luật."}, "21/05/2026": {"question": "Đồng chí cho biết theo Điều 9 Luật tố cáo quy định người tố cáo có nghĩa vụ như thế nào?", "answer": "Theo điều 9 Luật tố cáo, Người tố cáo có các nghĩa vụ sau đây:\n- Nêu rõ họ, tên, địa chỉ của mình;\n- Trình bày trung thực về nội dung tố cáo; cung cấp thông tin, tài liệu liên quan đến nội dung tố cáo mà mình có được;\n- Chịu trách nhiệm trước pháp luật về nội dung tố cáo của mình;\n- Bồi thường thiệt hại do hành vi cố ý tố cáo sai sự thật của mình gây ra."}, "22/05/2026": {"question": "Đồng chí cho biết theo điều 10, Luật tố cáo quy định người bị tố cáo có quyền như thế nào?", "answer": "Theo điều 10 Luật tố cáo, Người bị tố cáo có các quyền sau đây:\n- Được thông báo về nội dung tố cáo;\n- Đưa ra chứng cứ để chứng minh nội dung tố cáo là không đúng sự thật;\n- Nhận thông báo kết luận nội dung tố cáo;\n- Yêu cầu cơ quan, tổ chức, cá nhân có thẩm quyền xử lý người cố ý tố cáo sai sự thật, người cố ý giải quyết tố cáo trái pháp luật;\n- Được khôi phục quyền, lợi ích hợp pháp bị xâm phạm, được xin lỗi, cải chính công khai, được bồi thường thiệt hại do việc tố cáo, giải quyết tố cáo không đúng gây ra."}, "23/05/2026": {"question": "Đồng chí cho biết theo điều 10, Luật tố cáo quy định người bị tố cáo có nghĩa vụ như thế nào?", "answer": "Theo điều 10 Luật tố cáo, Người bị tố cáo có các nghĩa vụ sau đây:\n- Giải trình bằng văn bản về hành vi bị tố cáo; cung cấp thông tin, tài liệu liên quan khi cơ quan, tổ chức, cá nhân có thẩm quyền yêu cầu;\n- Chấp hành nghiêm chỉnh quyết định xử lý của cơ quan, tổ chức, cá nhân có thẩm quyền;\n- Bồi thường, bồi hoàn thiệt hại do hành vi trái pháp luật của mình gây ra."}, "24/05/2026": {"question": "Đồng chí cho biết theo điều 11, Luật tố cáo quy định người giải quyết tố cáo có quyền như thế nào?", "answer": "Theo điều 11 Luật tố cáo, Người giải quyết tố cáo có các quyền sau đây:\n- Yêu cầu người tố cáo cung cấp thông tin, tài liệu liên quan đến nội dung tố cáo;\n- Yêu cầu người bị tố cáo giải trình bằng văn bản về hành vi bị tố cáo;\n- Yêu cầu cơ quan, tổ chức, cá nhân cung cấp thông tin, tài liệu liên quan đến nội dung tố cáo;\n- Tiến hành các biện pháp kiểm tra, xác minh, thu thập chứng cứ để giải quyết tố cáo theo quy định của pháp luật; áp dụng các biện pháp theo thẩm quyền để ngăn chặn, chấm dứt hành vi vi phạm pháp luật;\n- Kết luận về nội dung tố cáo;\n- Quyết định xử lý theo thẩm quyền hoặc kiến nghị cơ quan, tổ chức, cá nhân có thẩm quyền xử lý theo quy định của pháp luật."}, "25/05/2026": {"question": "Đồng chí cho biết theo điều 11, Luật tố cáo quy định người giải quyết tố cáo có nghĩa vụ như thế nào?", "answer": "- Bảo đảm khách quan, trung thực, đúng pháp luật trong việc giải quyết tố cáo;\n- Áp dụng các biện pháp cần thiết theo thẩm quyền hoặc yêu cầu cơ quan chức năng áp dụng các biện pháp để bảo vệ người tố cáo, người thân thích của người tố cáo, người cung cấp thông tin có liên quan đến việc tố cáo;\n- Không tiết lộ thông tin gây bất lợi cho người bị tố cáo khi chưa có kết luận về nội dung tố cáo;\n- Chịu trách nhiệm trước pháp luật về việc giải quyết tố cáo;\n- Bồi thường, bồi hoàn thiệt hại do hành vi giải quyết tố cáo trái pháp luật của mình gây ra."}, "26/05/2026": {"question": "Đồng chí cho biết theo Luật tố cáo quy định trình tự giải quyết tố cáo như thế nào?", "answer": "Theo điều 18, Luật tố cáo quy định trình tự giải quyết tố cáo như sau:\n1. Tiếp nhận, xử lý thông tin tố cáo;\n2. Xác minh nội dung tố cáo;\n3. Kết luận nội dung tố cáo;\n4. Xử lý tố cáo của người giải quyết tố cáo;\n5. Công khai kết luận nội dung tố cáo, quyết định xử lý hành vi vi phạm bị tố cáo."}, "27/05/2026": {"question": "Đồng chí cho biết theo Luật tố cáo quy định về thời gian giải quyết tố cáo cụ thể như thế nào?", "answer": "Theo điều 21, Luật tố cáo quy định:\n- Thời hạn giải quyết tố cáo là 60 ngày, kể từ ngày thụ lý giải quyết tố cáo; đối với vụ việc phức tạp thì thời hạn giải quyết là 90 ngày, kể từ ngày thụ lý giải quyết tố cáo.\n-. Trong trường hợp cần thiết, người có thẩm quyền giải quyết tố cáo có thể gia hạn thời hạn giải quyết một lần nhưng không quá 30 ngày; đối với vụ việc phức tạp thì không quá 60 ngày."}, "28/05/2021": {"question": "Đồng chí cho biết theo Luật tố cáo quy định về việc tiếp nhận và xử lý như thế nào?", "answer": "Theo điều 20, quy định: Khi nhận được tố cáo thì người giải quyết tố cáo có trách nhiệm phân loại và xử lý như sau:\n- Nếu tố cáo thuộc thẩm quyền giải quyết của mình thì trong thời hạn 10 ngày, kể từ ngày nhận được đơn tố cáo, phải kiểm tra, xác minh họ, tên, địa chỉ của người tố cáo và quyết định việc thụ lý hoặc không thụ lý giải quyết tố cáo, đồng thời thông báo cho người tố cáo biết lý do việc không thụ lý, nếu có yêu cầu; trường hợp phải kiểm tra, xác minh tại nhiều địa điểm thì thời hạn kiểm tra, xác minh có thể dài hơn nhưng không quá 15 ngày;\n- Nếu tố cáo không thuộc thẩm quyền giải quyết của mình thì trong thời hạn 05 ngày làm việc, kể từ ngày nhận được đơn tố cáo, người tiếp nhận phải chuyển đơn tố cáo cho cơ quan, tổ chức, cá nhân có thẩm quyền giải quyết và thông báo cho người tố cáo, nếu có yêu cầu. Trường hợp người tố cáo đến tố cáo trực tiếp thì người tiếp nhận tố cáo hướng dẫn người tố cáo đến tố cáo với cơ quan, tổ chức, cá nhân có thẩm quyền giải quyết."}, "29/05/2026": {"question": "Đồng chí cho biết theo Luật tố cáo quy định 07 hành vi bị cấm cuối cùng như thế nào?", "answer": "- Cản trở việc thực hiện quyền tố cáo; đe doạ, trả thù, trù dập, xúc phạm người tố cáo.\n- Bao che người bị tố cáo.\n- Cố ý tố cáo sai sự thật; kích động, cưỡng ép, dụ dỗ, mua chuộc người khác tố cáo sai sự thật; mạo danh người khác để tố cáo.\n- Mua chuộc, hối lộ người giải quyết tố cáo; đe doạ, trả thù, xúc phạm người giải quyết tố cáo.\n- Lợi dụng việc tố cáo để tuyên truyền chống Nhà nước, xâm phạm lợi ích của Nhà nước; xuyên tạc, vu khống, gây rối an ninh, trật tự công cộng, xúc phạm danh dự, nhân phẩm, uy tín của người khác.\n- Đưa tin sai sự thật về việc tố cáo và giải quyết tố cáo.\n- Vi phạm các quy định khác của pháp luật về tố cáo và giải quyết tố cáo."}, "30/05/2026": {"question": "Đồng chí cho biết theo điều 11, Luật tố cáo quy định người giải quyết tố cáo có nghĩa vụ như thế nào?", "answer": "- Bảo đảm khách quan, trung thực, đúng pháp luật trong việc giải quyết tố cáo;\n- Áp dụng các biện pháp cần thiết theo thẩm quyền hoặc yêu cầu cơ quan chức năng áp dụng các biện pháp để bảo vệ người tố cáo, người thân thích của người tố cáo, người cung cấp thông tin có liên quan đến việc tố cáo;\n- Không tiết lộ thông tin gây bất lợi cho người bị tố cáo khi chưa có kết luận về nội dung tố cáo;\n- Chịu trách nhiệm trước pháp luật về việc giải quyết tố cáo;\n- Bồi thường, bồi hoàn thiệt hại do hành vi giải quyết tố cáo trái pháp luật của mình gây ra."}, "31/05/2026": {"question": "Đồng chí cho biết, theo điểm 3, điều 129 của Điều lệnh quản lý bộ đội, quy định về phòng, chống cháy nổ như thế nào?", "answer": "Theo điểm 3, điều 129 của Điều lệnh quản lý bộ đội, quy định về phòng, chống cháy nổ như sau: Từng đơn vị phải có đủ phương tiện chữa cháy cần thiết để ở vị trí thuận tiện; phải bảo quản cẩn thận và thường xuyên kiểm tra chất lượng của các phương tiện chữa cháy."}, "01/06/2026": {"question": "Đồng chí cho biết theo quy định kỷ luật vi phạm các quy định về xuất cảnh, nhập cảnh, quá cảnh, cư trú và đi lại phạt tiền từ 30.000.000 đồng đến 40.000.000 đồng đối với những hành vi nào?", "answer": "a) Giả mạo hồ sơ, giấy tờ để được cấp hộ chiếu hoặc giấy tờ khác có giá trị thay hộ chiếu, thị thực, thẻ tạm trú, thẻ thường trú;\n\tb) Làm giả hộ chiếu hoặc giấy tờ khác có giá trị thay hộ chiếu, thị thực, thẻ tạm trú, thẻ thường trú hoặc dấu kiểm chứng;\n\tc) Trốn vào đại sứ quán, lãnh sự quán hoặc trụ sở cơ quan, tổ chức quốc tế đóng tại Việt Nam;\n\td) Người nước ngoài cư trú tại Việt Nam mà không được phép của cơ quan có thẩm quyền;\n\tđ) Tổ chức, đưa dẫn hoặc mô giới cho người khác xuất cảnh, nhập cảnh Việt Nam trái phép."}, "02/06/2026": {"question": "Đồng chí cho biết theo quy định kỷ luật vi phạm các quy định về xuất cảnh, nhập cảnh, quá cảnh, cư trú và đi lại phạt tiền từ 5.000.000 đồng đến 10.000.000 đồng đối với những hành vi nào?", "answer": "a) Chủ phương tiện, người điều khiển các loại phương tiện chuyên chở người nhập cảnh, xuất cảnh Việt Nam trái phép;\n\tb) Sử dụng hộ chiếu giả, giấy tờ có giá trị thay hộ chiếu giả, thị thực giả, thẻ tạm trú giả, thẻ thường trú giả, giấu kiểm chứng giả để xuất cảnh, nhập cảnh, quá cảnh, cư trú."}, "04/06/2026": {"question": "Đồng chí cho biết theo quy định kỷ luật vi phạm các quy định về xuất cảnh, nhập cảnh, quá cảnh, cư trú và đi lại phạt tiền từ 30.000.000 đồng đến 40.000.000 đồng đối với những hành vi nào?", "answer": "a) Giả mạo hồ sơ, giấy tờ để được cấp hộ chiếu hoặc giấy tờ khác có giá trị thay hộ chiếu, thị thực, thẻ tạm trú, thẻ thường trú;\n\tb) Làm giả hộ chiếu hoặc giấy tờ khác có giá trị thay hộ chiếu, thị thực, thẻ tạm trú, thẻ thường trú hoặc dấu kiểm chứng;\n\tc) Trốn vào đại sứ quán, lãnh sự quán hoặc trụ sở cơ quan, tổ chức quốc tế đóng tại Việt Nam;\n\td) Người nước ngoài cư trú tại Việt Nam mà không được phép của cơ quan có thẩm quyền;\n\tđ) Tổ chức, đưa dẫn hoặc mô giới cho người khác xuất cảnh, nhập cảnh Việt Nam trái phép."}, "05/06/2026": {"question": "Đồng chí cho biết theo Điều 20 của Bộ luật Dân sự năm 2015 quy định người thành niên từ mấy tuổi trở lên?", "answer": "Theo Điều  20 của Bộ luật Dân sự năm 2015 quy định, người thành niên là người từ đủ mười tám tuổi trở lên."}, "06/06/2026": {"question": "Đồng chí cho biết theo điểm 1, Điều 22 của Bộ luật Dân sự năm 2015 quy định một người mất năng lực hành vi dân sự khi nào?", "answer": "Khi một người do bị bệnh tâm thần hoặc mắc bệnh khác mà không thể nhận thức, làm chủ được hành vi thì theo yêu cầu của người có quyền, lợi ích liên quan hoặc của cơ quan, tổ chức hữu quan, Tòa án ra quyết định tuyên bố người này là người mất năng lực hành vi dân sự trên cơ sở kết luận giám định pháp y tâm thần.\nKhi không còn căn cứ tuyên bố một người mất năng lực hành vi dân sự thì theo yêu cầu của chính người đó hoặc của người có quyền, lợi ích liên quan hoặc của cơ quan, tổ chức hữu quan, Tòa án ra quyết định hủy bỏ quyết định tuyên bố mất năng lực hành vi dân sự."}, "07/06/2026": {"question": "Đồng chí cho biết theo Điều 105 của Bộ luật Dân sự năm 2015 quy định tài sản là gì?", "answer": "- Tài sản là vật, tiền, giấy tờ có giá và quyền tài sản.\n- Tài sản bao gồm bất động sản và động sản. Bất động sản và động sản có thể là tài sản hiện có và tài sản hình thành trong tương lai."}, "08/06/2026": {"question": "Đồng chí cho biết theo điểm 1, Điều 107 của Bộ luật Dân sự năm 2015 quy định bất động sản gồm những gì?", "answer": "a) Đất đai;\nb) Nhà, công trình xây dựng gắn liền với đất đai;\nc) Tài sản khác gắn liền với đất đai, nhà, công trình xây dựng;\nd) Tài sản khác theo quy định của pháp luật."}, "10/06/2026": {"question": "Đồng chí cho biết theo điểm 1, Điều 119 của Bộ luật Dân sự năm 2015 quy định giao dịch dân sự có những hình thức nào?", "answer": "Giao dịch dân sự được thể hiện bằng lời nói, bằng văn bản hoặc bằng hành vi cụ thể.\nGiao dịch dân sự thông qua phương tiện điện tử dưới hình thức thông điệp dữ liệu theo quy định của pháp luật về giao dịch điện tử được coi là giao dịch bằng văn bản."}, "11/06/2026": {"question": "Đồng chí cho biết theo Điều 158 của Bộ luật Dân sự năm 2015 quy định quyền sở hữu là gì?", "answer": "Theo Điều 158 của Bộ luật Dân sự năm 2015 quy định: Quyền sở hữu bao gồm quyền chiếm hữu, quyền sử dụng và quyền định đoạt tài sản của chủ sở hữu theo quy định của luật."}, "12/06/2026": {"question": "Đồng chí cho biết theo điểm 1, Điều 163 của Bộ luật Dân sự năm 2015 quy định bảo vệ quyền sở hữu như thế nào?", "answer": "Theo 1, Điều 163 của Bộ luật Dân sự năm 2015 quy định: Không ai có thể bị hạn chế, bị tước đoạt trái luật quyền sở hữu, quyền khác đối với tài sản."}, "13/06/2026": {"question": "Đồng chí cho biết theo điểm 1, Điều 166 của Bộ luật Dân sự năm 2015 quy định  quyền đòi lại tài sản như thế nào?", "answer": "Theo điểm 1, Điều 166 của Bộ luật Dân sự năm 2015 quy định: Chủ sở hữu, chủ thể có quyền khác đối với tài sản có quyền đòi lại tài sản từ người chiếm hữu, người sử dụng tài sản, người được lợi về tài sản không có căn cứ pháp luật."}, "14/06/2026": {"question": "Đồng chí cho biết theo Điều 27 của Luật Doanh nghiệp năm 2014, trình tự, thủ tục đăng ký doanh nghiệp như thế nào?", "answer": "1. Người thành lập doanh nghiệp hoặc người được ủy quyền gửi hồ sơ đăng ký doanh nghiệp theo quy định tại Luật này cho Cơ quan đăng ký kinh doanh.\n2. Cơ quan đăng ký kinh doanh có trách nhiệm xem xét tính hợp lệ của hồ sơ đăng ký doanh nghiệp và cấp Giấy chứng nhận đăng ký doanh nghiệp trong thời hạn 03 ngày làm việc, kể từ ngày nhận hồ sơ. Trường hợp từ chối cấp Giấy chứng nhận đăng ký doanh nghiệp thì phải thông báo bằng văn bản cho người thành lập doanh nghiệp biết. Thông báo phải nêu rõ lý do và các yêu cầu sửa đổi, bổ sung hồ sơ.\n3. Chính phủ quy định chi tiết trình tự, thủ tục, hồ sơ đăng ký doanh nghiệp, sự phối hợp liên thông giữa các cơ quan trong cấp Giấy chứng nhận đăng ký doanh nghiệp, đăng ký lao động, bảo hiểm xã hội và đăng ký doanh nghiệp qua mạng thông tin điện tử."}, "15/06/2026": {"question": "Đồng chí cho biết theo Điều 29 của Luật Doanh nghiệp năm 2014, giấy chứng nhận đăng ký doanh nghiệp có mấy nội dung?", "answer": "Theo Điều 29 của Luật Doanh nghiệp năm 2014, giấy chứng nhận đăng ký doanh nghiệp có 4 nội dung:\n1. Tên doanh nghiệp và mã số doanh nghiệp.\n2. Địa chỉ trụ sở chính của doanh nghiệp.\n3. Họ, tên, địa chỉ thường trú, quốc tịch, số Thẻ căn cước công dân, Giấy chứng minh nhân dân, Hộ chiếu …\n4. Vốn điều lệ."}, "16/06/2026": {"question": "Đồng chí cho biết theo điểm 1, Điều 38 của Luật Doanh nghiệp năm 2014, tên doanh nghiệp gồm những gì?", "answer": "a) Loại hình doanh nghiệp. Tên loại hình doanh nghiệp được viết là “công ty trách nhiệm hữu hạn” hoặc “công ty TNHH” đối với công ty trách nhiệm hữu hạn; được viết là “công ty cổ phần” hoặc “công ty CP” đối với công ty cổ phần; được viết là “công ty hợp danh” hoặc “công ty HD” đối với công ty hợp danh\nb) Tên riêng. Tên riêng được viết bằng các chữ cái trong bảng chữ cái tiếng Việt, các chữ F, J, Z, W, chữ số và ký hiệu."}, "17/06/2026": {"question": "Đồng chí cho biết tại điểm 1, Điều 6 Luật Nghĩa vụ quân sự năm 2015 quy định đối tượng nào có nghĩa vụ phục vụ tại ngũ trong Quân đội nhân dân?", "answer": "Theo điểm 1, Điều 6, Luật Nghĩa vụ quân sự năm 2015 quy định Công dân nam trong độ tuổi thực hiện nghĩa vụ quân sự có nghĩa vụ phục vụ tại ngũ trong Quân đội nhân dân."}, "18/06/2026": {"question": "Đồng chí cho biết theo Điều 30 của Luật Nghĩa vụ quân sự năm 2015 quy định độ tuổi gọi nhập ngũ là bao nhiêu?", "answer": "Theo Điều 30 của Luật Nghĩa vụ quân sự năm 2015 quy định Công dân đủ 18 tuổi được gọi nhập ngũ; độ tuổi gọi nhập ngũ từ đủ 18 tuổi đến hết 25 tuổi; công dân được đào tạo trình độ cao đẳng, đại học đã được tạm hoãn gọi nhập ngũ thì độ tuổi gọi nhập ngũ đến hết 27 tuổi."}, "19/06/2026": {"question": "Đồng chí cho biết theo Điều 21, Luật Nghĩa vụ quân sự năm 2015 quy định Bộ trưởng BQP được quyền giữ HSQ, BS phục vụ tại ngũ thêm một thời gian không quá bao lâu so với thời hạn quy định?", "answer": "Theo Điều 21, Luật Nghĩa vụ quân sự năm 2015 quy định Bộ trưởng BQP được quyền giữ HSQ, BS phục vụ tại ngũ thêm một thời gian không quá 6 tháng."}, "20/06/2026": {"question": "Đồng chí cho biết Ủy ban nhân dân cấp nào có trách nhiệm tổ chức chuẩn bị cho công dân phục vụ tại ngũ và gọi công dân nhập ngũ?", "answer": "Ủy ban nhân dân cấp huyện có trách nhiệm tổ chức chuẩn bị cho công dân phục vụ tại ngũ và gọi công dân nhập ngũ."}, "21/06/2026": {"question": "Đồng chí cho biết hàng năm, việc gọi công dân nhập ngũ, thời gian gọi nhập ngũ và số lượng công dân nhập ngũ trong năm do cấp nào quyết định?", "answer": "Hàng năm, việc gọi công dân nhập ngũ, thời gian gọi nhập ngũ và số lượng công dân nhập ngũ trong năm do Chính phủ quyết định."}, "22/06/2026": {"question": "Đồng chí cho biết việc gọi công dân nhập ngũ được tiến hành theo lệnh của cấp nào?", "answer": "Việc gọi công dân nhập ngũ được tiến hành theo lệnh của Bộ trưởng Bộ Quốc phòng."}, "23/06/2026": {"question": "Đồng chí cho biết thời gian xuất ngũ của hạ sĩ quan và binh sĩ phải được thông báo cho quân nhân trước mấy tháng?", "answer": "Thời gian xuất ngũ của hạ sĩ quan và binh sĩ phải được thông báo cho quân nhân trước 1 tháng."}, "24/06/2026": {"question": "Đ/c cho biết, Hạ sĩ quan và binh sĩ đã hết hạn phục vụ tại ngũ có thể tình nguyện ở lại phục vụ trên hạn định thêm 1 thời gian ít nhất là bao nhiêu lâu?", "answer": "Hạ sĩ quan và binh sĩ đã hết hạn phục vụ tại ngũ có thể tình nguyện ở lại phục vụ trên hạn định thêm 1 thời gian ít nhất là 12 tháng."}, "25/06/2026": {"question": "Đ/c cho biết theo quy định của Điều lệnh quản lý bộ đội, chiến sĩ có mấy chức trách?", "answer": "Theo quy định của Điều lệnh quản lý bộ đội, chiến sĩ có 5 chức trách."}, "26/06/2026": {"question": "Đ/c cho biết theo quy định của Điều lệnh quản lý bộ đội, trực ban nội vụ ở đơn vị có mấy chức trách?", "answer": "Theo quy định của Điều lệnh quản lý bộ đội, trực ban nội vụ ở đơn vị có 7 chức trách."}, "27/06/2026": {"question": "Đ/c cho biết theo quy định công tác quản lý VKTB ở cấp Tiểu đội, trung đội và đại đội được quy định như thế nào?", "answer": "Công tác quản lý VKTB ở cấp tiểu đội, trung đội và đại đội được quy định như sau: Tiểu đội trưởng và tương đương phải kiểm tra hàng ngày, trung đội trưởng và tương đương hai ngày ít nhất phải kiểm tra một tiểu đội, đại đội trưởng và tương đương phải kiểm tra ít nhất một trung đội."}, "28/06/2026": {"question": "Đ/c cho biết theo quy định hình thức báo động luyện tập được chia thành bao nhiêu hình thức?", "answer": "Theo quy định hình thức báo động luyện tập được chia thành 4 hình thức."}, "29/06/2026": {"question": "Đ/c cho biết theo quy định chế độ kiểm tra sáng được tiến hành hàng ngày (trừ ngày nghỉ và ngày chào cờ) tổ chức kiểm tra là bao nhiêu phút?", "answer": "Theo quy định chế độ kiểm tra sáng được tiến hành hàng ngày (trừ ngày nghỉ và ngày chào cờ) tổ chức kiểm tra là 10 phút."}, "30/06/2026": {"question": "Đồng chí cho biết theo quy định, người chỉ huy và trực ban đơn vị phải thực dậy trước bao nhiêu phút để trực tiếp ra hiệu lệnh báo thức và đi kiểm tra, đôn đốc mọi quân nhân, đơn vị dậy đúng giờ?", "answer": "Theo quy định, người chỉ huy và trực ban đơn vị phải thực dậy trước 10 phút để trực tiếp ra hiệu lệnh báo thức và đi kiểm tra, đôn đốc mọi quân nhân, đơn vị dậy đúng giờ.\nII. NỘI DUNG MỖI TUẦN 01 ĐIỀU LUẬT"}}, "weekly": {"Tuần 1 tháng 1": "Điều 35, Điều lệnh quản lý bộ đội, quy định về “Chức trách, nhiệm vụ của chiến sĩ”\n1. Hiểu biết và thực hiện đúng nghĩa vụ, trách nhiệm, vinh dự của người chiến sĩ trong quân đội.\n2. Rèn luyện bản lĩnh chiến đấu, rèn luyện thể lực, tích cực học tập để nâng cao trình độ về mọi mặt. Dũng cảm không sợ gian khổ, hy sinh, kiên quyết hoàn thành mọi nhiệm vụ.\n3. Giữ tốt và sử dụng thành thạo các loại vũ khí, trang bị, quân trang và dụng cụ được giao. Có nhiệm vụ bảo vệ tài sản chung.\n4. Tự giác chấp hành nghiêm kỷ luật quân đội và mệnh lệnh, chỉ thị của cấp trên, pháp luật của Nhà nước.\n5. Tích cực xây dựng đơn vị, đoàn kết thương yêu đồng chí, đồng đội, tôn trọng cấp trên, tôn trọng và giúp đỡ nhân dân.", "Tuần 2 tháng 1": "Điều 36, Điều lệnh quản lý bộ đội, quy định về “Phong cách quân nhân”\n1. Trong quan hệ quân nhân, mọi quân nhân phải giữ gìn phẩm chất đạo đức cách mạng và nghiêm chỉnh tuân theo những yêu cầu của sinh hoạt xã hội. Trong quan hệ với nhân dân, quân nhân phải kính trọng người già, yêu mến trtẻ em, tôn trọng phụ nữ.\n2. Quân nhân phải là người có ý thức tổ chức kỷ luật, có tinh thần đoàn kết, tương trợ và có nếp sống văn minh, lành mạnh; thái độ hoà nhã, khiêm tốn; biết tự chủ và tự trọng trong lời nói cũng như trong hành động:\na) Mặc quân phục phải theo đúng quy định của quân đội. Không viết vẽ lên quân phục;\nb) Đầu tóc phải gọn gàng, không xăm chàm trên thân thể, chỉ được nhuộm tóc màu đen, nam quân nhân tóc mai, tóc gáy cắt ngắn, không để râu(...);\nc) Đi, đứng phải giữ đúng tư thế, tác phong quân nhân, khi đi tập thể thành đội ngũ, có người chỉ huy;\nd) Gương mẫu chấp hành pháp luật Nhà nước và những quy tắc sinh hoạt xã hội.\n3. Cấm quân nhân uống rượu, bia trong khi thực hiện nhiệm vụ; uống say rượu, bia ở mọi lúc, mọi nơi; hút thuốc lá nơi công cộng; mua, bán, tàng trữ và sử dụng các chất kích thích, chất gây nghiện dưới bất kỳ hình thức nào theo quy định của pháp luật.", "Tuần 3 tháng 1": "Điểm 2, Điều 52, Điều lệnh quản lý bộ đội, quy định về “Học tập ngoài thao trường”\na) Đi và về phải thành đội ngũ. thời gian đi và về không tính vào thời gian học tập. Nếu một lần đi (về) trên một giờ được tính một nửa vào thời gian học tập;\nb) Trước khi học tập, người phụ trách hoặc trực ban lớp học phải tập hợp bộ đội, kiểm tra quân số, trang phục, vũ khí, học cụ, khám súng sau đó báo cáo với giáo viên;\nc) Phải chấp hành nghiêm kỷ luật thao trường, luyện tập nơi gần địch phải có kế hoạch sẵn sàng chiến đấu. Súng, đạn, trang bị chưa dùng trong luyện tập phải có người canh gác. Hết giờ luyện tập, người phụ trách hoặc trực ban lớp phải tập hợp bộ đội, khám súng, kiểm tra quân số, vũ khí, học cụ và các trang bị khác, chỉnh đốn hàng ngũ, báo cáo giáo viên cho bộ đội nghỉ, sau đó chỉ huy bộ đội về doanh trại hoặc nghỉ tại thao trường.", "Tuần 4 tháng 1": "Điểm 1, điều 129 Điều lệnh quản lý bộ đội, quy định về “Phòng, chống cháy nổ”\nMọi quân nhân có trách  nhiệm chấp hành nghiêm chỉnh các quy định về phòng chống cháy nổ ở mọi nơi, mọi hoàn cảnh; phải được huấn luyện cách sử dụng các loại phương tiện chữa cháy, nổ của đơn vị;\n\tKhi phát hiện nguy cơ có thể xảy ra cháy, nổ cần có biện pháp xử lý kịp thời, đồng thời báo cáo người chỉ huy và người có liên quan. Khi xảy ra cháy nổ phải nhanh chóng cứu chữa bằng mọi phương tiện.", "Tuần 5 tháng 1": "Điều 334. Tội huỷ hoại vũ khí quân dụng, phương tiện kỹ thuật quân sự \n1. Người nào hủy hoại vũ khí quân dụng, phương tiện kỹ thuật quân sự, nếu không thuộc trường hợp quy định tại Điều 85 và Điều 231 của Bộ luật này, thì bị phạt tù từ hai năm đến bảy năm.\n2. Phạm tội trong chiến đấu, trong khu vực có chiến sự hoặc gây hậu quả nghiêm trọng, thì bị phạt tù từ năm năm đến mười hai năm.\n3. Phạm tội gây hậu quả rất nghiêm trọng thì bị phạt tù từ mười năm đến hai mươi năm.\n4. Phạm tội gây hậu quả đặc biệt nghiêm trọng thì bị phạt tù hai mươi năm, tù chung thân hoặc tử hình.", "Tuần 1 tháng 2": "Điều 7, Luật Phòng chống tác hại thuốc lá năm 2012  Quyền và nghĩa vụ của công dân trong phòng, chống tác hại của thuốc lá”\n\t1. Được sống, làm việc trong môi trường không có khói thuốc lá.\n\t2. Yêu cầu người hút thuốc lá không hút thuốc lá tại địa điểm có quy định cấm hút thuốc lá.\n\t3. Vận động, tuyên truyền người khác không sử dụng thuốc lá, cai nghiện thuốc lá.\n\t4. Yêu cầu cơ quan, tổ chức, cá nhân có thẩm quyền xử lý người có hành vi hút thuốc lá tại địa điểm có quy định cấm hút thuốc lá.\n\t5. Phản ánh hoặc tố cáo cơ quan, người có thẩm quyền không xử lý hành vi hút thuốc lá tại địa điểm có quy định cấm hút thuốc lá.", "Tuần 2 tháng 2": "Điều 8, Luật Phòng chống tác hại thuốc lá năm 2012  “Hợp tác quốc tế trong phòng, chống tác hại của thuốc lá”\n\t1. Mở rộng hợp tác quốc tế trong phòng, chống tác hại của thuốc lá với các nước, tổ chức quốc tế trên cơ sở bình đẳng, tôn trọng độc lập, chủ quyền, phù hợp với pháp luật mỗi nước, pháp luật và thông lệ quốc tế.\n\t2. Nội dung hợp tác quốc tế bao gồm:\n\ta) Hợp tác trong phòng, chống thuốc lá nhập lậu, thuốc lá giả;\n\tb) Hợp tác trong việc cấm quảng cáo, khuyến mại và tài trợ thuốc lá xuyên biên giới;\n\tc) Hợp tác trong nghiên cứu khoa học, đào tạo, hỗ trợ kinh phí và trao đổi thông tin liên quan đến phòng, chống tác hại của thuốc lá.", "Tuần 3 tháng 2": "Điều 9, Luật Phòng chống tác hại thuốc lá năm 2012  “Các hành vi bị nghiêm cấm”\n\t1. Sản xuất, mua bán, nhập khẩu, tàng trữ, vận chuyển thuốc lá giả, sản phẩm được thiết kế có hình thức hoặc kiểu dáng như bao, gói hoặc điếu thuốc lá; mua bán, tàng trữ, vận chuyển nguyên liệu thuốc lá, thuốc lá nhập lậu.\n\t2. Quảng cáo, khuyến mại thuốc lá; tiếp thị thuốc lá trực tiếp tới người tiêu dùng dưới mọi hình thức.\n\t3. Tài trợ của tổ chức, cá nhân kinh doanh thuốc lá, trừ trường hợp quy định tại Điều 16 của Luật này.\n\t4. Người chưa đủ 18 tuổi sử dụng, mua, bán thuốc lá.\n\t5. Sử dụng người chưa đủ 18 tuổi mua, bán thuốc lá.\n\t6. Bán, cung cấp thuốc lá cho người chưa đủ 18 tuổi.\n\t7. Bán thuốc lá bằng máy bán thuốc lá tự động; hút, bán thuốc lá tại địa điểm có quy định cấm.\n\t8. Sử dụng hình ảnh thuốc lá trên báo chí, xuất bản phẩm dành riêng cho trẻ em.\n\t9. Vận động, ép buộc người khác sử dụng thuốc lá.", "Tuần 4 tháng 2": "Điều 11, Luật Phòng chống tác hại thuốc lá năm 2012 “Địa điểm cấm hút thuốc lá hoàn toàn”\n\t1. Địa điểm cấm hút thuốc lá hoàn toàn trong nhà và trong phạm vi khuôn viên bao gồm:\n\ta) Cơ sở y tế;\n\tb) Cơ sở giáo dục, trừ các cơ sở quy định tại điểm b khoản 2 Điều này;\n\tc) Cơ sở chăm sóc, nuôi dưỡng, vui chơi, giải trí dành riêng cho trẻ em;\n\td) Cơ sở hoặc khu vực có nguy cơ cháy, nổ cao.\n\t2. Địa điểm cấm hút thuốc lá hoàn toàn trong nhà bao gồm:\n\ta) Nơi làm việc;\n\tb) Trường cao đẳng, đại học, học viện;\n\tc) Địa điểm công cộng, trừ các trường hợp quy định tại khoản 1 Điều này và khoản 1 Điều 12 của Luật này.\n\t3. Phương tiện giao thông công cộng bị cấm hút thuốc lá hoàn toàn bao gồm ô tô, tàu bay, tàu điện.", "Tuần 1 tháng 3": "Điều 14, Luật Phòng chống tác hại thuốc lá năm 2012 “Quyền và trách nhiệm của người đứng đầu, người quản lý địa điểm cấm hút thuốc lá”\n\t1. Người đứng đầu, người quản lý địa điểm cấm hút thuốc lá có các quyền sau đây:\n\ta) Buộc người vi phạm chấm dứt việc hút thuốc lá tại địa điểm cấm hút thuốc lá; xử phạt vi phạm hành chính theo quy định của pháp luật;\n\tb) Yêu cầu người vi phạm quy định cấm hút thuốc lá ra khỏi cơ sở của mình;\n\tc) Từ chối tiếp nhận hoặc cung cấp dịch vụ cho người vi phạm quy định cấm hút thuốc lá nếu người đó tiếp tục vi phạm sau khi đã được nhắc nhở.\n\t2. Người đứng đầu, người quản lý địa điểm cấm hút thuốc lá có trách nhiệm sau đây:\n\ta) Thực hiện quy định tại Điều 6 của Luật này;\n\tb) Tổ chức thực hiện, hướng dẫn, kiểm tra, đôn đốc mọi người thực hiện đúng quy định về cấm hút thuốc lá tại địa điểm thuộc quyền quản lý, điều hành; treo biển có chữ hoặc biểu tượng cấm hút thuốc lá tại địa điểm cấm hút thuốc lá.", "Tuần 2 tháng 3": "Điều 13, Thông tư 143/TT-BQP “Chống mệnh lệnh”\n\t1. Không chấp hành mệnh lệnh hoặc không thực hiện nhiệm vụ khi người chỉ huy trực tiếp hoặc cấp có thẩm quyền giao mà chưa đến mức bị truy cứu trách nhiệm hình sự thì bị kỷ luật cảnh cáo hoặc hạ bậc lương, giáng cấp bậc quân hàm.\n\t2. Nếu vi phạm một trong các trường hợp sau thì bị kỷ luật từ hạ bậc lương, giáng cấp bậc quân hàm, giáng chức, cách chức, tước quân hàm sĩ quan đến tước danh hiệu quân nhân, buộc thôi việc:\n\ta) Là chỉ huy hoặc sĩ quan;\n\tb) Lôi kéo người khác tham gia;\n\tc) Trong sẵn sàng chiến đấu;\n\tb) Đã bị xử lý kỷ luật mà còn vi phạm.", "Tuần 4 tháng 3": "Điểm 1, điều 129 Điều lệnh quản lý bộ đội, quy định về “Phòng, chống cháy nổ”\nMọi quân nhân có trách  nhiệm chấp hành nghiêm chỉnh các quy định về phòng chống cháy nổ ở mọi nơi, mọi hoàn cảnh; phải được huấn luyện cách sử dụng các loại phương tiện chữa cháy, nổ của đơn vị;\n\tKhi phát hiện nguy cơ có thể xảy ra cháy, nổ cần có biện pháp xử lý kịp thời, đồng thời báo cáo người chỉ huy và người có liên quan. Khi xảy ra cháy nổ phải nhanh chóng cứu chữa bằng mọi phương tiện.", "Tuần 1 tháng 4": "Điều 20, Thông tư 143/TT-BQP “Đào ngũ”\n\t1. Tự ý rời khỏi đơn vị lần đầu quá 03 (ba) ngày đối với sĩ quan, quân nhân chuyên nghiệp, công nhân và viên chức quốc phòng; quá 07 (bảy) ngày đối với hạ sĩ quan, binh sĩ nhưng không thuộc các trường hợp được quy định tại Bộ luật hình sự thì bị kỷ luật từ cảnh cáo đến hạ bậc lương, giáng cấp bậc quân hàm.\n\t2. Nếu vi phạm một trong các trường hợp sau thì bị kỷ luật từ giáng chức, cách chức, tước quân hàm sĩ quan đến tước danh hiệu quân nhân, buộc thôi việc:\n\ta) Gây hậu quả nhưng chưa đến mức độ nghiêm trọng;\n\tb) Khi đang làm nhiệm vụ;\n\tc) Đã bị xử lý kỷ luật mà còn vi phạm;\n\td) Lôi kéo người khác tham gia.", "Tuần 2 tháng 4": "Điều 332 Bộ Luật Hình sự năm 2015 “Tội vi phạm các quy định về bảo đảm an toàn trong chiến đấu hoặc trong huấn luyện”\n1. Người nào không chấp hành nghiêm chỉnh những quy định bảo đảm an toàn trong chiến đấu hoặc trong huấn luyện gây hậu quả nghiêm trọng, thì bị phạt cải tạo không giam giữ đến ba năm hoặc phạt tù từ một năm đến năm năm.\n2. Phạm tội gây hậu quả rất nghiêm trọng hoặc đặc biệt nghiêm trọng, thì bị phạt tù từ ba năm đến mười năm.", "Tuần 3 tháng 4": "Điều 333 Bộ Luật Hình sự năm 2015 “Tội vi phạm các quy định về sử dụng vũ khí quân dụng” \n1. Người nào vi phạm các quy định về sử dụng vũ khí quân dụng gây hậu quả nghiêm trọng, thì bị phạt cải tạo không giam giữ đến ba năm hoặc phạt tù từ sáu tháng đến năm năm.\n2. Phạm tội trong khu vực có chiến sự hoặc gây hậu quả rất nghiêm trọng hoặc đặc biệt nghiêm trọng, thì bị phạt tù từ ba năm đến mười năm.", "Tuần 4 tháng 4": "Điều 334 Bộ Luật Hình sự năm 2015  “Tội huỷ hoại vũ khí quân dụng, phương tiện kỹ thuật quân sự” \n1. Người nào hủy hoại vũ khí quân dụng, phương tiện kỹ thuật quân sự, nếu không thuộc trường hợp quy định tại Điều 85 và Điều 231 của Bộ luật này, thì bị phạt tù từ hai năm đến bảy năm.\n2. Phạm tội trong chiến đấu, trong khu vực có chiến sự hoặc gây hậu quả nghiêm trọng, thì bị phạt tù từ năm năm đến mười hai năm.\n3. Phạm tội gây hậu quả rất nghiêm trọng thì bị phạt tù từ mười năm đến hai mươi năm.\n4. Phạm tội gây hậu quả đặc biệt nghiêm trọng thì bị phạt tù hai mươi năm, tù chung thân hoặc tử hình.", "Tuần 5 tháng 4": "Điều 335. Tội làm mất hoặc vô ý làm hư hỏng vũ khí quân dụng, phương tiện kỹ thuật quânsự   \n1. Người nào được giao quản lý, được trang bị vũ khí quân dụng, phương tiện kỹ 3thuật quân sự mà làm mất hoặc vô ý làm hư hỏng gây hậu quả nghiêm trọng, thì bị phạt cải tạo không giam giữ đến ba năm hoặc phạt tù từ sáu tháng đến năm năm.\n2. Phạm tội gây hậu quả rất nghiêm trọng hoặc đặc biệt nghiêm trọng, thì bị phạt tù từ ba năm đến bảy năm.", "Tuần 1 tháng 5": "Điều 335 Bộ Luật Hình sự năm 2015 “Tội làm mất hoặc vô ý làm hư hỏng vũ khí quân dụng, phương tiện kỹ thuật quân sự”    \n1. Người nào được giao quản lý, được trang bị vũ khí quân dụng, phương tiện kỹ 3thuật quân sự mà làm mất hoặc vô ý làm hư hỏng gây hậu quả nghiêm trọng, thì bị phạt cải tạo không giam giữ đến ba năm hoặc phạt tù từ sáu tháng đến năm năm.\n2. Phạm tội gây hậu quả rất nghiêm trọng hoặc đặc biệt nghiêm trọng, thì bị phạt tù từ ba năm đến bảy năm.", "Tuần 2 tháng 5": "Điều 336 Bộ Luật Hình sự năm 2015 “Tội vi phạm chính sách đối với thương binh, tử sĩ trong chiến đấu” \n1. Người nào có trách nhiệm mà cố ý bỏ thương binh, tử sĩ tại trận địa hoặc không chăm sóc, cứu chữa thương binh gây hậu quả nghiêm trọng, thì bị phạt cải tạo không giam giữ đến ba năm hoặc phạt tù từ ba tháng đến ba năm.\n2. Phạm tội gây hậu quả rất nghiêm trọng thì bị phạt tù từ hai năm đến bảy năm.\n3. Phạm tội gây hậu quả đặc biệt nghiêm trọng thì bị phạt tù từ năm năm đến mười năm.\n4. Người nào chiếm đoạt di vật của tử sĩ, thì bị phạt cải tạo không giam giữ đến ba năm hoặc phạt tù từ ba tháng đến ba năm.", "Tuần 3 tháng 5": "Điều 337 Bộ Luật Hình sự năm 2015 “Tội chiếm đoạt hoặc huỷ hoại chiến lợi phẩm”   \n1. Người nào trong chiến đấu hoặc khi thu dọn chiến trường mà chiếm đoạt hoặc huỷ hoại chiến lợi phẩm, thì bị phạt cải tạo không giam giữ đến ba năm hoặc phạt tù từ sáu tháng đến năm năm.\n2. Phạm tội thuộc một trong các trường hợp sau đây, thì bị phạt tù từ ba năm đến tám năm:\na) Là chỉ huy hoặc sĩ quan;\nb) Chiến lợi phẩm có giá trị lớn hoặc rất lớn;\nc) Gây hậu quả nghiêm trọng hoặc rất nghiêm trọng.\n3. Phạm tội trong trường hợp chiến lợi phẩm có giá trị đặc biệt lớn hoặc gây hậu quả đặc biệt nghiêm trọng, thì bị phạt tù từ bảy năm đến mười hai năm.", "Tuần 4 tháng 5": "Điều 338 Bộ Luật Hình sự năm 2015  “Tội quấy nhiễu nhân dân”   \n1. Người nào có hành vi quấy nhiễu nhân dân đã bị xử lý kỷ luật về hành vi này mà còn vi phạm hoặc gây hậu quả nghiêm trọng, thì bị phạt cải tạo không giam giữ đến ba năm hoặc phạt tù từ ba tháng đến ba năm.\n2. Phạm tội thuộc một trong các trường hợp sau đây, thì bị phạt tù từ hai năm đến bảy năm:\na) Là chỉ huy hoặc sĩ quan;\nb) Lôi kéo người khác phạm tội;\nc) Phạm tội trong khu vực có chiến sự hoặc trong khu vực đã có lệnh ban bố tình trạng khẩn cấp;\nd) Gây hậu quả rất nghiêm trọng hoặc đặc biệt nghiêm trọng.", "Tuần 1 tháng 6": "Điều 6, Luật Khiếu nại  “Về các hành vi bị cấm”   \n1. Cản trở, gây phiền hà cho người thực hiện quyền khiếu nại; đe doạ, trả thù, trù dập người khiếu nại.\n2. Thiếu trách nhiệm trong việc giải quyết khiếu nại; không giải quyết khiếu nại; làm sai lệch các thông tin, tài liệu, hồ sơ vụ việc khiếu nại; cố ý giải quyết khiếu nại trái pháp luật.\n3. Ra quyết định giải quyết khiếu nại không bằng hình thức quyết định.\n4. Bao che cho người bị khiếu nại; can thiệp trái pháp luật vào việc giải quyết khiếu nại.\n5. Cố tình khiếu nại sai sự thật;\n6. Kích động, xúi giục, cưỡng ép, dụ dỗ, mua chuộc, lôi kéo người khác tập trung đông người khiếu nại, gây rối an ninh trật tự công cộng.\n7. Lợi dụng việc khiếu nại để tuyên truyền chống Nhà nước, xâm phạm lợi ích của Nhà nước; xuyên tạc, vu khống, đe dọa, xúc phạm uy tín, danh dự của cơ quan, tổ chức, người có trách nhiệm giải quyết khiếu nại, người thi hành nhiệm vụ, công vụ khác.\n8. Vi phạm quy chế tiếp công dân;\n9. Vi phạm các quy định khác của pháp luật về khiếu nại và giải quyết khiếu nại.", "Tuần 2 tháng 6": "Điều 26, Thông tư 143/TT-BQP “Vi phạm các quy định về bảo đảm an toàn”\n1. Vi phạm các quy định phòng chống cháy nổ; bảo đảm an toàn trong huấn luyện, công tác, lao động, học tập, sinh hoạt và an toàn giao thông, thì bị kỷ luật khiển trách hoặc cảnh cáo.\n2. Nếu vi phạm một trong các trường hợp sau thì bị kỷ luật từ giáng chức, cách chức, hạ bậc lương đến giáng cấp bậc quân hàm:\na) Đã bị xử lý kỷ luật mà còn vi phạm;\nb) Là người có chuyên môn nghiệp vụ hoặc thiếu trách nhiệm trong việc ngăn chặn hậu quả;\nc) Để xảy ra mất an toàn về người, vũ khí, trang bị, phương tiện, tài sản.", "Tuần 3 tháng 6": "Điều 4, Luật Nghĩa vụ quân sự “Nghĩa vụ quân sự”\n1. Nghĩa vụ quân sự là nghĩa vụ vẻ vang của công dân phục vụ trong Quân đội nhân dân. Thực hiện nghĩa vụ quân sự bao gồm phục vụ tại ngũ và phục vụ trong ngạch dự bị của Quân đội nhân dân.\n2. Công dân trong độ tuổi thực hiện nghĩa vụ quân sự, không phân biệt dân tộc, thành phần xã hội, tín ngưỡng, tôn giáo, trình độ học vấn, nghề nghiệp, nơi cư trú phải thực hiện nghĩa vụ quân sự theo quy định của Luật này.\n3. Công dân phục vụ trong lực lượng Cảnh sát biển và thực hiện nghĩa vụ tham gia Công an nhân dân được coi là thực hiện nghĩa vụ quân sự tại ngũ.\n4. Công dân thuộc một trong các trường hợp sau đây được công nhận hoàn thành nghĩa vụ quân sự tại ngũ trong thời bình:\na) Dân quân tự vệ nòng cốt đã hoàn thành nghĩa vụ tham gia dân quân tự vệ, trong đó có ít nhất 12 tháng làm nhiệm vụ dân quân tự vệ thường trực;\nb) Hoàn thành nhiệm vụ tham gia Công an xã liên tục từ đủ 36 tháng trở lên;\nc) Cán bộ, công chức, viên chức, sinh viên tốt nghiệp đại học trở lên, đã được đào tạo và phong quân hàm sĩ quan dự bị;\nd) Thanh niên đã tốt nghiệp đại học, cao đẳng, trung cấp tình nguyện phục vụ tại đoàn kinh tế - quốc phòng từ đủ 24 tháng trở lên theo Đề án do Thủ tướng Chính phủ quyết định;\nđ) Công dân phục vụ trên tàu kiểm ngư từ đủ 24 tháng trở lên.", "Tuần 4 tháng 6": "Điều 4, Luật Nghĩa vụ quân sự “Quyền và nghĩa vụ của hạ sĩ quan, binh sĩ”\n1. Hạ sĩ quan, binh sĩ được Nhà nước bảo đảm chế độ, chính sách ưu đãi phù hợp với tính chất hoạt động của Quân đội nhân dân.\n2. Hạ sĩ quan, binh sĩ có nghĩa vụ:\na) Tuyệt đối trung thành với Tổ quốc, Nhân dân, với Đảng và Nhà nước Cộng hòa xã hội chủ nghĩa Việt Nam;\nb) Sẵn sàng chiến đấu, hy sinh bảo vệ độc lập, chủ quyền, thống nhất, toàn vẹn lãnh thổ của Tổ quốc; bảo vệ Nhân dân, Đảng, Nhà nước và chế độ xã hội chủ nghĩa; hoàn thành mọi nhiệm vụ được giao và thực hiện nghĩa vụ quốc tế;\nc) Bảo vệ tài sản và lợi ích của Nhà nước, cơ quan, tổ chức; bảo vệ tính mạng, tài sản, quyền và lợi ích hợp pháp của Nhân dân; tham gia bảo vệ an ninh quốc gia và trật tự, an toàn xã hội theo quy định của pháp luật;\nd) Chấp hành nghiêm đường lối, chủ trương của Đảng, chính sách, pháp luật của Nhà nước, Điều lệnh, Điều lệ của Quân đội nhân dân;\nđ) Học tập chính trị, quân sự, văn hóa, khoa học, kỹ thuật, nghiệp vụ; rèn luyện tính tổ chức, ý thức kỷ luật và thể lực; nâng cao bản lĩnh chính trị, bản lĩnh chiến đấu."}};

// ── CONSTANTS ─────────────────────────────────────────────────────
// CORS proxy để vượt giới hạn cross-origin
const CORS_PROXY = 'https://api.allorigins.win/raw?url=';
const CORS_PROXY2 = 'https://corsproxy.io/?';

// Nguồn tin VNExpress
const URL_THEGIOI  = 'https://vnexpress.net/the-gioi';
const URL_TRONGNUOC = 'https://vnexpress.net/thoi-su';

// ── TIỆN ÍCH NGÀY THÁNG ─────────────────────────────────────────
function getToday() {
  const d = new Date();
  const dd = String(d.getDate()).padStart(2, '0');
  const mm = String(d.getMonth() + 1).padStart(2, '0');
  const yyyy = d.getFullYear();
  return { dd, mm, yyyy, full: `${dd}/${mm}/${yyyy}` };
}

function formatDateVN(date) {
  const days = ['Chủ Nhật','Thứ Hai','Thứ Ba','Thứ Tư','Thứ Năm','Thứ Sáu','Thứ Bảy'];
  const d = new Date(date);
  const dayName = days[d.getDay()];
  return `${dayName}, ngày ${String(d.getDate()).padStart(2,'0')} tháng ${String(d.getMonth()+1).padStart(2,'0')} năm ${d.getFullYear()}`;
}

// Tính tuần thứ mấy trong tháng (tuần 1 = ngày 1-7, tuần 2 = ngày 8-14, ...)
function getWeekOfMonth(day) {
  return Math.ceil(day / 7);
}

// ── KHỞI TẠO ────────────────────────────────────────────────────
document.addEventListener('DOMContentLoaded', () => {
  const { dd, mm, yyyy, full } = getToday();
  const now = new Date();

  // Hiển thị ngày trong header
  document.getElementById('header-date').textContent = formatDateVN(now);
  document.getElementById('update-time').textContent =
    String(now.getHours()).padStart(2,'0') + ':' +
    String(now.getMinutes()).padStart(2,'0');

  // Tải tất cả các phần
  loadWorldNews();
  loadVietnamNews();
  loadBacHo();
  loadPhapLuat();
});

