// PHẦN 2: TIN THẾ GIỚI (VNExpress)
// ═══════════════════════════════════════════════════════════════════
async function loadWorldNews() {
  await loadVNExpressNews('world-news', URL_THEGIOI, 'tin thế giới');
}

// ═══════════════════════════════════════════════════════════════════
// PHẦN 3: TIN TRONG NƯỚC (VNExpress)
// ═══════════════════════════════════════════════════════════════════
async function loadVietnamNews() {
  await loadVNExpressNews('vietnam-news', URL_TRONGNUOC, 'tin trong nước');
}

// ── HÀM CHÍNH LẤY TIN VNEXPRESS ──────────────────────────────────
async function loadVNExpressNews(containerId, url, label) {
  const container = document.getElementById(containerId);

  try {
    // Thử proxy 1
    let html = await fetchWithProxy(url, CORS_PROXY);
    if (!html) {
      // Thử proxy 2
      html = await fetchWithProxy(url, CORS_PROXY2);
    }
    if (!html) throw new Error('Không thể tải trang');

    const articles = parseVNExpressHTML(html, url);

    if (!articles.length) throw new Error('Không tìm thấy bài viết');

    renderNews(container, articles);

  } catch (err) {
    console.warn(`Lỗi tải ${label}:`, err);
    container.innerHTML = `
      <div class="error-msg">
        <i class="fas fa-exclamation-circle"></i>
        <div>
          <strong>Không thể tải ${label}</strong><br/>
          <small>Vui lòng kiểm tra kết nối hoặc truy cập trực tiếp:
          <a href="${url}" target="_blank" style="color:inherit">${url}</a></small>
        </div>
      </div>`;
  }
}

async function fetchWithProxy(url, proxy) {
  try {
    const proxyUrl = proxy + encodeURIComponent(url);
    const res = await fetch(proxyUrl, { signal: AbortSignal.timeout(10000) });
    if (!res.ok) return null;
    return await res.text();
  } catch {
    return null;
  }
}

// ── PHÂN TÍCH HTML VNEXPRESS ──────────────────────────────────────
function parseVNExpressHTML(html, sourceUrl) {
  const parser = new DOMParser();
  const doc = parser.parseFromString(html, 'text/html');
  const articles = [];

  // Chọn các article element từ VNExpress
  const selectors = [
    'article.item-news',
    '.item-news',
    'article[class*="item"]',
    '.list-news article',
    '.sidebar-1 article'
  ];

  let items = [];
  for (const sel of selectors) {
    items = [...doc.querySelectorAll(sel)];
    if (items.length >= 3) break;
  }

  // Nếu không tìm được, thử dạng khác
  if (items.length < 3) {
    items = [...doc.querySelectorAll('h3.title-news a, h2.title-news a')]
      .map(a => a.closest('article') || a.closest('li') || a.parentElement)
      .filter(Boolean);
  }

  const now = Date.now();

  for (const item of items.slice(0, 6)) {
    // Lấy title
    const titleEl = item.querySelector('h3 a, h2 a, .title-news a, a.title-news');
    if (!titleEl) continue;

    const title = titleEl.textContent.trim();
    if (!title || title.length < 10) continue;

    // Lấy link
    let link = titleEl.href || '';
    if (!link.startsWith('http')) {
      link = 'https://vnexpress.net' + (link.startsWith('/') ? link : '/' + link);
    }

    // Lấy mô tả
    const descEl = item.querySelector('p.description, p.txt-brief, .description, p');
    const description = descEl ? descEl.textContent.trim() : '';

    // Lấy thời gian
    const timeEl = item.querySelector('span.time-count, .time-count, time, .time, span[class*="time"]');
    let dateStr = timeEl ? timeEl.textContent.trim() : '';
    let timeAgo = parseTimeVNExpress(dateStr);

    // Lấy ảnh
    const imgEl = item.querySelector('img[src], img[data-src]');
    const imgSrc = imgEl ? (imgEl.dataset.src || imgEl.src || '') : '';

    articles.push({ title, link, description, dateStr, timeAgo, imgSrc });
  }

  // Nếu vẫn không có, thử cách backup - tìm thẻ a có href vnexpress
  if (articles.length === 0) {
    const links = [...doc.querySelectorAll('a[href*="vnexpress.net"]')]
      .filter(a => {
        const href = a.href;
        const txt = a.textContent.trim();
        return txt.length > 20 && href.includes('-') && !href.includes('#');
      })
      .slice(0, 6);

    for (const a of links) {
      articles.push({
        title: a.textContent.trim(),
        link: a.href,
        description: '',
        dateStr: 'Hôm nay',
        timeAgo: 0,
        imgSrc: ''
      });
    }
  }

  return articles.slice(0, 3);
}

function parseTimeVNExpress(str) {
  if (!str) return Infinity;
  str = str.toLowerCase().trim();
  if (str.includes('phút trước') || str.includes('phut truoc')) {
    const m = parseInt(str);
    return isNaN(m) ? 0 : m * 60 * 1000;
  }
  if (str.includes('giờ trước') || str.includes('gio truoc')) {
    const h = parseInt(str);
    return isNaN(h) ? 0 : h * 3600 * 1000;
  }
  if (str.includes('hôm qua') || str.includes('hom qua')) return 30 * 3600 * 1000;
  return 5 * 3600 * 1000; // mặc định 5 giờ
}

function getTimeBadge(timeAgo) {
  if (timeAgo < 6 * 3600 * 1000) return { cls: 'badge-today', label: 'Hôm nay' };
  if (timeAgo < 36 * 3600 * 1000) return { cls: 'badge-recent', label: 'Gần đây' };
  return { cls: 'badge-old', label: 'Cũ hơn' };
}

function renderNews(container, articles) {
  if (!articles.length) {
    container.innerHTML = `<div class="fallback-msg"><i class="fas fa-info-circle"></i> Chưa có tin mới hôm nay.</div>`;
    return;
  }

  const html = articles.map(art => {
    const badge = getTimeBadge(art.timeAgo);
    const desc = art.description
      ? `<p class="news-summary">${escapeHtml(art.description.slice(0, 200))}${art.description.length > 200 ? '…' : ''}</p>`
      : '';
    return `
    <a class="news-item" href="${escapeHtml(art.link)}" target="_blank" rel="noopener">
      <div class="news-meta">
        <span class="news-date"><i class="fas fa-clock"></i> ${escapeHtml(art.dateStr || 'Hôm nay')}</span>
        <span class="news-badge ${badge.cls}">${badge.label}</span>
      </div>
      <div class="news-title">${escapeHtml(art.title)}</div>
      ${desc}
      <div class="news-source"><i class="fas fa-external-link-alt"></i> vnexpress.net &rarr; Đọc bài đầy đủ</div>
    </a>`;
  }).join('');

  container.innerHTML = `<div class="news-list">${html}</div>`;
}

