// PHẦN 4: LỜI BÁC HỒ DẠY
// ═══════════════════════════════════════════════════════════════════
async function loadBacHo() {
  const container = document.getElementById('bac-ho-content');
  const { dd, mm, yyyy } = getToday();
  const url = `https://loibacday.com/${dd}-${mm}`;

  try {
    let html = await fetchWithProxy(url, CORS_PROXY);
    if (!html) html = await fetchWithProxy(url, CORS_PROXY2);
    if (!html) throw new Error('Không tải được');

    const doc = new DOMParser().parseFromString(html, 'text/html');

    // Tìm nội dung lời dạy
    const selectors = [
      '.entry-content p',
      '.post-content p',
      'article p',
      '.content p',
      'main p'
    ];

    let text = '';
    for (const sel of selectors) {
      const els = [...doc.querySelectorAll(sel)].filter(p => p.textContent.trim().length > 30);
      if (els.length) {
        text = els.slice(0, 3).map(p => p.textContent.trim()).join('\n\n');
        break;
      }
    }

    if (!text) throw new Error('Không tìm thấy nội dung');

    container.innerHTML = `
      <div class="bachday-box">
        <div class="bachday-quote">${escapeHtml(text)}</div>
        <div class="bachday-date">
          <i class="fas fa-calendar-alt"></i>
          Ngày ${dd} tháng ${mm} năm xưa
          &nbsp;|&nbsp;
          <a href="${url}" target="_blank" rel="noopener" style="color:#92400e">Nguồn: loibacday.com</a>
        </div>
      </div>`;

  } catch (err) {
    console.warn('Lỗi tải lời Bác Hồ:', err);
    container.innerHTML = `
      <div class="fallback-msg">
        <i class="fas fa-exclamation-triangle"></i>
        <div>
          Chưa tải được lời Bác Hồ dạy hôm nay.
          Xem trực tiếp tại: <a href="https://loibacday.com/${dd}-${mm}" target="_blank">loibacday.com/${dd}-${mm}</a>
        </div>
      </div>`;
  }
}

